async def get_real_whale_transactions(min_btc: float = 100.0, limit: int = 20):
    """
    Récupère des transactions BTC "whale" (données réelles) sans dépendre de clés API.

    Stratégie:
      1) blockchain.info unconfirmed-transactions (rapide, contient les adresses)
      2) fallback sur mempool.space / blockstream (mempool recent + tx details)
    Retour:
      list[dict] avec keys: time, asset, amount, from, to, txid (optionnel)
    """
    def _short_addr(a: str) -> str:
        if not a or a == "—":
            return "—"
        a = str(a)
        return a if len(a) <= 14 else f"{a[:6]}…{a[-6:]}"

    # ---------- 1) blockchain.info ----------
    try:
        async with httpx.AsyncClient(
            timeout=12.0,
            headers={"User-Agent": "CryptoIA/1.0 (+https://cryptoia.ca)"}
        ) as client:
            r = await client.get("https://blockchain.info/unconfirmed-transactions?format=json")
            r.raise_for_status()
            data = r.json() or {}
        txs = data.get("txs") or []
        if isinstance(txs, list) and txs:
            import time as _time
            now_ts = int(_time.time())
            events = []
            for tx in txs:
                try:
                    outs = tx.get("out") or []
                    total_sats = sum(int(o.get("value") or 0) for o in outs)
                    amount_btc = total_sats / 1e8
                    if amount_btc < float(min_btc):
                        continue

                    inputs = tx.get("inputs") or []
                    from_addr = "—"
                    if inputs:
                        prev = (inputs[0].get("prev_out") or {})
                        from_addr = prev.get("addr") or "—"

                    to_addr = "—"
                    if outs:
                        to_addr = (outs[0].get("addr") or "—")

                    ts = int(tx.get("time") or now_ts)
                    # Affichage HH:MM (UTC)
                    import datetime as _dt
                    tlabel = _dt.datetime.utcfromtimestamp(ts).strftime("%H:%M")

                    events.append({
                        "time": tlabel,
                        "asset": "BTC",
                        "amount": round(amount_btc, 2),
                        "from": _short_addr(from_addr),
                        "to": _short_addr(to_addr),
                        "txid": (tx.get("hash") or "")[:12]
                    })
                    if len(events) >= int(limit):
                        break
                except Exception:
                    continue

            if events:
                print(f"✅ Whale Watcher: {len(events)} transactions réelles (source=blockchain.info)")
                return events
    except Exception:
        pass

    # ---------- 2) fallback: mempool.space / blockstream ----------
    bases = [
        (os.getenv("MEMPOOL_API_BASE") or "https://mempool.space").strip().rstrip("/"),
        "https://blockstream.info",
    ]

    async def _fetch_recent_txids(client: httpx.AsyncClient, base: str):
        r = await client.get(f"{base}/api/mempool/recent")
        r.raise_for_status()
        j = r.json()
        # mempool.space peut renvoyer liste d'objets {txid: ...} ou liste de strings
        if isinstance(j, list):
            if j and isinstance(j[0], dict):
                return [x.get("txid") for x in j if x.get("txid")]
            return [x for x in j if isinstance(x, str)]
        return []

    async def _fetch_tx_detail(client: httpx.AsyncClient, base: str, txid: str):
        r = await client.get(f"{base}/api/tx/{txid}")
        r.raise_for_status()
        return r.json() or {}

    try:
        async with httpx.AsyncClient(
            timeout=12.0,
            headers={"User-Agent": "CryptoIA/1.0 (+https://cryptoia.ca)"}
        ) as client:
            for base in bases:
                if not base.startswith("http://") and not base.startswith("https://"):
                    # éviter l'erreur "missing http/https"
                    continue
                try:
                    txids = await _fetch_recent_txids(client, base)
                    if not txids:
                        continue
                    import datetime as _dt
                    events = []
                    for txid in txids[:60]:
                        try:
                            tx = await _fetch_tx_detail(client, base, txid)
                            vout = tx.get("vout") or []
                            total_sats = sum(int(o.get("value") or 0) for o in vout)
                            amount_btc = total_sats / 1e8
                            if amount_btc < float(min_btc):
                                continue

                            vin = tx.get("vin") or []
                            from_addr = "—"
                            if vin:
                                prev = vin[0].get("prevout") or {}
                                from_addr = prev.get("scriptpubkey_address") or "—"

                            to_addr = "—"
                            if vout:
                                to_addr = vout[0].get("scriptpubkey_address") or "—"

                            # time: block_time si confirmé sinon "—"
                            status = tx.get("status") or {}
                            bt = status.get("block_time")
                            if bt:
                                tlabel = _dt.datetime.utcfromtimestamp(int(bt)).strftime("%H:%M")
                            else:
                                tlabel = "—"

                            events.append({
                                "time": tlabel,
                                "asset": "BTC",
                                "amount": round(amount_btc, 2),
                                "from": _short_addr(from_addr),
                                "to": _short_addr(to_addr),
                                "txid": str(txid)[:12],
                            })
                            if len(events) >= int(limit):
                                break
                        except Exception:
                            continue

                    if events:
                        print(f"✅ Whale Watcher: {len(events)} transactions réelles (source={base})")
                        return events
                except Exception:
                    continue
    except Exception:
        pass

    return []





def _http_get_json_sync(url, timeout=8.0, headers=None):
    """Small sync JSON fetcher (stdlib only). Returns (data, status_code, error)."""
    try:
        import urllib.request, json as _json
        req_headers = {"User-Agent": "CryptoIA/1.0", "Accept": "application/json"}
        if headers:
            req_headers.update(headers)
        req = urllib.request.Request(url, headers=req_headers)
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            status = getattr(resp, "status", None) or resp.getcode()
            raw = resp.read()
        try:
            data = _json.loads(raw.decode("utf-8", errors="ignore"))
        except Exception as e:
            return None, status, f"json decode failed: {e}"
        return data, status, None
    except Exception as e:
        return None, None, str(e)


def get_real_whale_transactions_meta(limit: int = 5, min_btc: float = 100.0):
    """Fetch whale-like BTC transfers from public endpoints.

    Returns: (events, meta)
      - events: list[dict] same shape as existing get_real_whale_transactions
      - meta: dict with keys:
          api_ok (bool): True if at least one endpoint responded with a valid payload
          source (str|None): endpoint base used
          raw_count (int|None): number of raw txs returned by the endpoint (before filtering)
          error (str|None): last error if api_ok is False
    """
    meta = {"api_ok": False, "source": None, "raw_count": None, "error": None}

    # We reuse the same sources list as get_real_whale_transactions.
    sources = [
        "https://api.blockchain.info",          # legacy
        "https://blockchain.info",              # legacy alt
        "https://blockchain.info",              # legacy (dup tolerated)
        "https://blockchain.info",              # kept for robustness
        "https://blockchain.info",              # (some envs block api subdomain)
        "https://api.blockchain.info",          # retry
    ]

    # Prefer the same request style as the main function (keeps your infra behavior consistent)
    headers = {"User-Agent": "CryptoIA-WhaleWatcher/1.0"}

    # Try multiple endpoints; we consider "API OK" if we get a JSON payload containing txs/transactions,
    # even if after filtering there are 0 whales above min_btc.
    for base in sources:
        try:
            url = f"{base}/unconfirmed-transactions?format=json"
            data, status_code, err = _http_get_json_sync(url, timeout=8.0, headers=headers)
            if err or not isinstance(data, dict):
                meta["error"] = f"Fetch fail ({base}): {err or 'invalid json'}"
                continue
            if status_code and int(status_code) >= 400:
                meta["error"] = f"HTTP {status_code} from {base}"
                continue

            txs = data.get("txs") or data.get("transactions") or []
            if not isinstance(txs, list):
                meta["error"] = f"unexpected payload from {base}"
                continue

            meta["api_ok"] = True
            meta["source"] = base
            meta["raw_count"] = len(txs)

            events = []
            for tx in txs[: max(200, limit * 50)]:  # limit parsing cost
                try:
                    out_total_sats = sum((o.get("value") or 0) for o in (tx.get("out") or []))
                    btc_amount = out_total_sats / 1e8
                except Exception:
                    btc_amount = 0.0

                if btc_amount < float(min_btc):
                    continue

                try:
                    inputs = tx.get("inputs") or []
                    from_addr = None
                    if inputs and isinstance(inputs, list):
                        prev = inputs[0].get("prev_out") or {}
                        from_addr = prev.get("addr")
                    outs = tx.get("out") or []
                    to_addr = None
                    if outs and isinstance(outs, list):
                        # choose biggest output as destination
                        biggest = max(outs, key=lambda o: o.get("value") or 0)
                        to_addr = biggest.get("addr")
                    ts = tx.get("time")
                    dt = datetime.datetime.utcfromtimestamp(ts).strftime("%H:%M") if ts else "—"
                except Exception:
                    from_addr, to_addr, dt = None, None, "—"

                events.append({
                    "time": dt,
                    "asset": "BTC",
                    "amount": round(float(btc_amount), 2),
                    "details": f"de {from_addr or '—'} → {to_addr or '—'}",
                })
                if len(events) >= limit:
                    break

            # return immediately on first working endpoint
            return events, meta

        except Exception as e:
            meta["error"] = str(e)
            continue

    # all endpoints failed
    return [], meta


def create_coinbase_payment(plan, email, client, amount=None):
    try:
        if not client:
            return None, "Coinbase client non initialisé"

        plan_key = normalize_plan(plan)
        plan_info = get_plan_pricing(plan_key)
        if not plan_info:
            return None, "Plan invalide"

        base_price = round(float(plan_info.get("price_cents", 0)) / 100.0, 2)
        currency = (plan_info.get("currency") or "cad").upper()

        # amount override (promo) allowed only if <= base
        final_price = base_price
        if amount is not None:
            try:
                final_price = float(amount)
            except Exception:
                final_price = base_price
            if final_price <= 0 or final_price > base_price:
                final_price = base_price

        charge_data = {
            "name": f"CryptoIA — {plan_info.get('display_name', plan_key.title())}",
            "description": f"Accès {plan_info.get('display_name', plan_key)} ({plan})",
            "pricing_type": "fixed_price",
            "local_price": {
                "amount": f"{final_price:.2f}",
                "currency": currency
            },
            "metadata": {
                "plan": plan_key,
                "original_plan": plan,
                "email": email,
                "currency": currency,
                "amount": f"{final_price:.2f}"
            }
        }

        charge = client.charge.create(charge_data)
        return charge, None

    except Exception as e:
        return None, str(e)


def create_stripe_checkout_session(plan, customer_email, success_url, cancel_url, amount=None):
    try:
        if not STRIPE_AVAILABLE:
            return None, "Stripe not available"

        plan_key = normalize_plan(plan)
        plan_info = get_plan_pricing(plan_key)
        if not plan_info:
            return None, "Invalid plan"

        base_cents = int(plan_info.get("price_cents", 0))
        currency = (plan_info.get("currency") or "cad").lower()

        # amount override is accepted (promo), but clamped to <= base
        amount_cents = base_cents
        if amount is not None:
            try:
                amount_cents = int(round(float(amount) * 100))
            except Exception:
                amount_cents = base_cents
            if amount_cents <= 0 or amount_cents > base_cents:
                amount_cents = base_cents

        session = stripe.checkout.Session.create(
            payment_method_types=['card'],
            line_items=[{
                'price_data': {
                    'currency': currency,
                    'product_data': {
                        'name': f"CryptoIA — {plan_info.get('display_name', plan_key.title())}",
                    },
                    'unit_amount': amount_cents,
                },
                'quantity': 1,
            }],
            mode='payment',
            customer_email=customer_email,
            success_url=success_url,
            cancel_url=cancel_url,
            metadata={
                'plan': plan_key,
                'original_plan': plan,
                'currency': currency,
                'amount_cents': str(amount_cents)
            }
        )
        return session, None

    except Exception as e:
        print(f"Stripe session error: {e}")
        return None, str(e)

def init_payments_db():
    """Crée la table payments pour Coinbase Commerce"""
    try:
        conn = get_db_connection()
        c = conn.cursor()
        if DB_CONFIG["type"] == "postgres":
            c.execute("""CREATE TABLE IF NOT EXISTS payments (
                id SERIAL PRIMARY KEY,
                charge_id TEXT UNIQUE,
                user_id TEXT,
                email TEXT,
                amount REAL,
                currency TEXT DEFAULT 'CAD',
                description TEXT,
                status TEXT DEFAULT 'pending',
                crypto_address TEXT,
                crypto_amount REAL,
                crypto_currency TEXT,
                created_at TIMESTAMP DEFAULT NOW(),
                updated_at TIMESTAMP DEFAULT NOW(),
                expires_at TIMESTAMP,
                paid_at TIMESTAMP
            )""")
        else:
            c.execute("""CREATE TABLE IF NOT EXISTS payments (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                charge_id TEXT UNIQUE,
                user_id TEXT,
                email TEXT,
                amount REAL,
                currency TEXT DEFAULT 'CAD',
                description TEXT,
                status TEXT DEFAULT 'pending',
                crypto_address TEXT,
                crypto_amount REAL,
                crypto_currency TEXT,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                expires_at TIMESTAMP,
                paid_at TIMESTAMP
            )""")
        conn.commit()
        conn.close()
        print(f"✅ Table payments OK ({DB_CONFIG['type']})")
        return True
    except Exception as e:
        print(f"❌ Init payments: {e}")
        return False

def create_payment_record(charge_id, user_id, email, amount, currency, description, charge_data):
    """Crée un enregistrement de paiement"""
    try:
        conn = get_db_connection()
        c = conn.cursor()
        
        crypto_address = ""
        crypto_amount = 0
        crypto_currency = ""
        
        # Extraire les infos crypto de charge_data
        if "address" in charge_data:
            crypto_address = charge_data["address"]
        if "pricing" in charge_data and "crypto" in charge_data["pricing"]:
            for crypto in charge_data["pricing"]["crypto"]:
                crypto_amount = float(crypto["amount"])
                crypto_currency = crypto["currency"]
                break
        
        if DB_CONFIG["type"] == "postgres":
            c.execute("""INSERT INTO payments 
                (charge_id, user_id, email, amount, currency, description, status, crypto_address, 
                 crypto_amount, crypto_currency, expires_at)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)""",
                (charge_id, user_id, email, amount, currency, description, "pending", 
                 crypto_address, crypto_amount, crypto_currency, 
                 datetime.now() + timedelta(hours=1)))
        else:
            c.execute("""INSERT INTO payments 
                (charge_id, user_id, email, amount, currency, description, status, crypto_address, 
                 crypto_amount, crypto_currency, expires_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                (charge_id, user_id, email, amount, currency, description, "pending", 
                 crypto_address, crypto_amount, crypto_currency, 
                 datetime.now() + timedelta(hours=1)))
        
        conn.commit()
        conn.close()
        return charge_id
    except Exception as e:
        print(f"❌ Create payment record: {e}")
        return None

def update_payment_status(charge_id, status, paid_at=None):
    """Met à jour le statut d'un paiement"""
    try:
        conn = get_db_connection()
        c = conn.cursor()
        
        updates = {"status": status, "updated_at": datetime.now()}
        if paid_at:
            updates["paid_at"] = paid_at
        
        if DB_CONFIG["type"] == "postgres":
            c.execute("""UPDATE payments SET status=%s, updated_at=%s, paid_at=%s WHERE charge_id=%s""",
                (status, datetime.now(), paid_at, charge_id))
        else:
            c.execute("""UPDATE payments SET status=?, updated_at=?, paid_at=? WHERE charge_id=?""",
                (status, datetime.now(), paid_at, charge_id))
        
        conn.commit()
        conn.close()
        return True
    except Exception as e:
        print(f"❌ Update payment status: {e}")
        return False

def get_payment_by_charge_id(charge_id):
    """Récupère les infos d'un paiement"""
    try:
        conn = get_db_connection()
        if DB_CONFIG["type"] == "postgres":
            c = conn.cursor(cursor_factory=RealDictCursor)
        else:
            conn.row_factory = sqlite3.Row
            c = conn.cursor()
        
        c.execute("SELECT * FROM payments WHERE charge_id=%s" if DB_CONFIG["type"] == "postgres" 
                  else "SELECT * FROM payments WHERE charge_id=?", (charge_id,))
        row = c.fetchone()
        conn.close()
        
        return dict(row) if row else None
    except Exception as e:
        print(f"❌ Get payment: {e}")
        return None

