import os
import html as _html_mod

# Global fallbacks used by several pages (avoid NameError)
# SIDEBAR_FULL défini plus tard après SIDEBAR
cards_html = globals().get("cards_html", "")

def escape_html(value):
    """HTML-escape helper used in f-strings. Safe for None."""
    try:
        return _html_mod.escape(str(value), quote=True)
    except Exception:
        return ""

def get_current_user_from_session(request):
    """Return current user dict from request.state/session/cookies.

    Works even if SessionMiddleware changes or if only cookies are present.
    """
    try:
        u = getattr(request.state, "user", None)
        if isinstance(u, dict) and u:
            return u
    except Exception:
        pass

    try:
        sess = request.session  # type: ignore[attr-defined]
        if isinstance(sess, dict) and sess.get("user"):
            return sess.get("user")
        if isinstance(sess, dict):
            for k in ("username","email","role","plan","session_role"):
                if k in sess:
                    return {
                        "username": sess.get("username") or sess.get("email") or "",
                        "email": sess.get("email") or "",
                        "role": sess.get("role") or sess.get("session_role") or "user",
                        "plan": sess.get("plan") or "free",
                    }
    except Exception:
        pass

    return {"username": "", "email": "", "role": "guest", "plan": "free"}

def _is_admin_user(user: dict) -> bool:
    role = (user.get("role") or user.get("session_role") or "").strip().lower()
    username = (user.get("username") or user.get("email") or "").strip().lower()
    return role in {"admin","owner","superadmin"} or username == "admin"

def _admin_bypass_enabled() -> bool:
    """Bypass admin UNIQUEMENT en dev/local.

    Sécurité: en production, le bypass est forcé à False même si la variable est mal réglée.
    """
    env = (os.getenv("ENV") or os.getenv("RAILWAY_ENVIRONMENT") or os.getenv("ENVIRONMENT") or "").strip().lower()
    if env in {"prod", "production", "main"}:
        return False

    v = (os.getenv("ADMIN_BYPASS", "0") or "").strip().lower()
    return v in {"1", "true", "yes", "on"}

def _force_admin_on_request(request):
    admin_user = {"username": "admin", "email": "", "role": "admin", "plan": "elite"}
    try:
        request.state.user = admin_user
    except Exception:
        pass
    try:
        if hasattr(request, "session") and isinstance(request.session, dict):  # type: ignore[attr-defined]
            request.session["user"] = admin_user
            request.session["role"] = "admin"
            request.session["plan"] = "elite"
            request.session["username"] = "admin"
    except Exception:
        pass
    return admin_user

# =======================
# Rate Limiter (optionnel)
# =======================
# Le projet utilise parfois @limiter.limit(...) sur certains endpoints.
# Sur certains déploiements, SlowAPI n'est pas installé -> on évite le crash en fournissant un "no-op" limiter.
class _NoopLimiter:
    def limit(self, *args, **kwargs):
        def _decorator(fn):
            return fn
        return _decorator

limiter = _NoopLimiter()

try:
    from slowapi import Limiter as _SlowLimiter, _rate_limit_exceeded_handler as _slowapi_handler
    from slowapi.util import get_remote_address as _get_remote_address
    from slowapi.errors import RateLimitExceeded as _RateLimitExceeded
    from slowapi.middleware import SlowAPIMiddleware as _SlowAPIMiddleware

    limiter = _SlowLimiter(key_func=_get_remote_address)
    app.state.limiter = limiter
    app.add_exception_handler(_RateLimitExceeded, _slowapi_handler)
    app.add_middleware(_SlowAPIMiddleware)
    print("✅ Rate limiter (slowapi) initialisé")
except Exception as _e:
    # Pas bloquant: on garde le limiter no-op.
    print(f"⚠️ Rate limiter désactivé ({_e.__class__.__name__})")
# =============================
# Auto footer d'aide sur TOUTES les pages HTML
# (injecte le bloc "À quoi sert / Comment utiliser" en bas de page)
# =============================
try:
    from starlette.middleware.base import BaseHTTPMiddleware
    from starlette.responses import Response
except Exception:
    BaseHTTPMiddleware = None  # type: ignore
    Response = None  # type: ignore

if BaseHTTPMiddleware and Response:
    class HelpFooterMiddleware(BaseHTTPMiddleware):
        async def dispatch(self, request, call_next):
            response = await call_next(request)
            try:
                ct = (response.headers.get("content-type") or "").lower()
                path = (request.url.path or "")
                # Seulement HTML (pas API/static)
                if ("text/html" in ct) and (not path.startswith("/api")) and (not path.startswith("/static")):
                    body = b""
                    # Starlette responses can be streamed; gather safely
                    if hasattr(response, "body_iterator") and response.body_iterator is not None:
                        async for chunk in response.body_iterator:
                            body += chunk
                    else:
                        body = getattr(response, "body", b"") or b""
                    html_text = body.decode("utf-8", errors="ignore")
                    modified = False
                    if ("</body>" in html_text.lower()) and ("cryptoia-help-footer" not in html_text):
                        # Titre via <title> si possible
                        m = re.search(r"<title>(.*?)</title>", html_text, re.IGNORECASE | re.DOTALL)
                        title_guess = (re.sub(r"\s+", " ", m.group(1)).strip() if m else "CryptoIA")
                        insert = _build_help_block(path, title_guess)
                        # Insérer juste avant </body>
                        html_text = re.sub(r"</body>", insert + "\n</body>", html_text, flags=re.IGNORECASE)
                        body = html_text.encode("utf-8")
                        modified = True

                    # IMPORTANT: si la réponse était streamée, on doit la reconstruire (sinon body consommé)
                    new_headers = dict(response.headers)
                    new_headers.pop("content-length", None)
                    return Response(content=body, status_code=response.status_code, headers=new_headers, media_type="text/html")
            except Exception:
                # En cas de souci, on renvoie la réponse originale sans casser le site
                pass
            return response

_app = globals().get("app")
if _app is not None:
    _app.add_middleware(HelpFooterMiddleware)

# =============================
# Sidebar Injection Middleware
# Injecte automatiquement le SIDEBAR dans toutes les pages HTML qui ne l ont pas
# =============================
if BaseHTTPMiddleware and Response:
    class SidebarInjectionMiddleware(BaseHTTPMiddleware):
        """Middleware qui injecte le SIDEBAR dans toutes les pages HTML."""
        
        # Pages qui ne doivent PAS avoir le sidebar (login, admin, etc.)
        EXCLUDED_PATHS = {
            "/login", "/register", "/admin-login", "/logout",
            "/health", "/favicon.ico"
        }
        EXCLUDED_PREFIXES = ("/api", "/static", "/assets", "/css", "/js", "/img", "/_")
        
        async def dispatch(self, request, call_next):
            response = await call_next(request)
            try:
                ct = (response.headers.get("content-type") or "").lower()
                path = (request.url.path or "")
                
                # Verifier si on doit exclure cette page
                if path in self.EXCLUDED_PATHS:
                    return response
                for prefix in self.EXCLUDED_PREFIXES:
                    if path.startswith(prefix):
                        return response
                
                # Seulement HTML
                if "text/html" not in ct:
                    return response
                
                # Recuperer le body
                body = b""
                if hasattr(response, "body_iterator") and response.body_iterator is not None:
                    async for chunk in response.body_iterator:
                        body += chunk
                else:
                    body = getattr(response, "body", b"") or b""
                
                html_text = body.decode("utf-8", errors="ignore")
                
                # Verifier si le sidebar est deja present
                if 'class="sidebar"' in html_text or 'id="sidebar"' in html_text or "class='sidebar'" in html_text or "id='sidebar'" in html_text:
                    new_headers = dict(response.headers)
                    new_headers.pop("content-length", None)
                    return Response(content=body, status_code=response.status_code, headers=new_headers, media_type="text/html")
                
                # Verifier si cest une page HTML complete
                if "</body>" not in html_text.lower():
                    new_headers = dict(response.headers)
                    new_headers.pop("content-length", None)
                    return Response(content=body, status_code=response.status_code, headers=new_headers, media_type="text/html")
                
                # Recuperer le SIDEBAR global
                sidebar_html = globals().get("SIDEBAR", "")
                if not sidebar_html:
                    new_headers = dict(response.headers)
                    new_headers.pop("content-length", None)
                    return Response(content=body, status_code=response.status_code, headers=new_headers, media_type="text/html")
                
                # CSS pour ajuster le contenu principal avec le sidebar
                sidebar_wrapper_css = '<style>body{margin:0}.sidebar-injected-wrapper{margin-left:280px;min-height:100vh;transition:margin-left 0.3s ease}@media(max-width:768px){.sidebar-injected-wrapper{margin-left:0}.sidebar{transform:translateX(-100%);transition:transform 0.3s ease}.sidebar.active{transform:translateX(0)}}</style>'
                
                # Injecter le sidebar apres <body>
                body_match = re.search(r'<body[^>]*>', html_text, re.IGNORECASE)
                if body_match:
                    body_tag_end = body_match.end()
                    html_before = html_text[:body_tag_end]
                    html_after = html_text[body_tag_end:]
                    closing_body = re.search(r'</body>', html_after, re.IGNORECASE)
                    if closing_body:
                        content_before_close = html_after[:closing_body.start()]
                        content_after_close = html_after[closing_body.start():]
                        new_html = html_before + sidebar_wrapper_css + sidebar_html + '<div class="sidebar-injected-wrapper">' + content_before_close + '</div>' + content_after_close
                        body = new_html.encode("utf-8")
                
                new_headers = dict(response.headers)
                new_headers.pop("content-length", None)
                return Response(content=body, status_code=response.status_code, headers=new_headers, media_type="text/html")
            except Exception:
                pass
            return response

_sidebar_app = globals().get("app")
if _sidebar_app is not None:
    _sidebar_app.add_middleware(SidebarInjectionMiddleware)

