# =============================
# Market Data API v2 (réutilisable par toutes les pages)
# - Données réelles Binance/CoinGecko
# - Cache serveur + validations
# =============================
import math
from urllib.parse import urlencode

_V2_CACHE = {}  # key -> (ts, ttl, value)

def _cache_get(key: str):
    try:
        ts, ttl, val = _V2_CACHE.get(key, (0, 0, None))
        if val is not None and (time.time() - ts) < ttl:
            return val
    except Exception:
        pass
    return None

def _cache_set(key: str, val, ttl: int):
    try:
        _V2_CACHE[key] = (time.time(), ttl, val)
    except Exception:
        pass

def _validate_symbol(symbol: str) -> str:
    s = (symbol or "").strip().upper()
    if not re.fullmatch(r"[A-Z0-9]{2,20}", s):
        raise ValueError("Symbol invalide")
    return s

def _validate_interval(interval: str) -> str:
    i = (interval or "").strip()
    allowed = {"1m","3m","5m","15m","30m","1h","2h","4h","6h","8h","12h","1d","3d","1w"}
    if i not in allowed:
        raise ValueError("Interval invalide")
    return i

async def _http_get_json(url: str, params: dict | None = None, timeout: float = 10.0, headers: dict | None = None, cache_ttl: int = 0, **_kw):
    """GET JSON with small production hardening.

    - Supports query params.
    - Adds a stable User-Agent (helps avoid some public API blocks).
    - Converts HTTP 429 into a RateLimitError with a retry_after.
    """
    base_headers = {
        "User-Agent": "CryptoIA/1.0 (+https://www.cryptoia.ca)",
        "Accept": "application/json",
    }
    if headers:
        base_headers.update(headers)

    class RateLimitError(Exception):
        def __init__(self, retry_after: int = 60, status_code: int = 429, message: str = "rate limited"):
            super().__init__(message)
            self.retry_after = int(retry_after or 60)
            self.status_code = status_code

    # Keep the exception class accessible to callers
    globals()["_RateLimitError"] = RateLimitError

    # httpx path (preferred)
    if 'httpx' in globals() and httpx is not None:
        async with httpx.AsyncClient(timeout=timeout, headers=base_headers) as client:
            r = await client.get(url, params=params)
            if r.status_code == 429:
                ra = r.headers.get("Retry-After")
                try:
                    ra_i = int(ra) if ra is not None else 60
                except Exception:
                    ra_i = 60
                raise RateLimitError(retry_after=ra_i, status_code=429, message=f"HTTP 429 for {url}")
            r.raise_for_status()
            return r.json()

    # urllib fallback
    import urllib.request
    if params:
        url = url + ("&" if "?" in url else "?") + urlencode(params)

    req = urllib.request.Request(url, headers=base_headers)
    try:
        with urllib.request.urlopen(req, timeout=timeout) as resp:
            body = resp.read().decode("utf-8", errors="ignore")
            return json.loads(body)
    except Exception as e:
        # best effort: detect 429 in urllib errors
        msg = str(e)
        if "HTTP Error 429" in msg:
            raise RateLimitError(retry_after=60, status_code=429, message=msg)
        raise


@app.get("/api/v2/market/ticker")
async def api_v2_market_ticker(symbol: str = "BTCUSDT"):
    try:
        sym = _validate_symbol(symbol)
        cache_key = f"ticker:{sym}"
        cached = _cache_get(cache_key)
        if cached is not None:
            return {"ok": True, "cached": True, **cached}

        url = "https://api.binance.com/api/v3/ticker/24hr?" + urlencode({"symbol": sym})
        data = await _http_get_json(url, timeout=8.0)
        out = {
            "symbol": sym,
            "price": float(data.get("lastPrice") or 0),
            "change_24h_pct": float(data.get("priceChangePercent") or 0),
            "volume": float(data.get("volume") or 0),
            "quote_volume": float(data.get("quoteVolume") or 0),
        }
        _cache_set(cache_key, out, ttl=20)
        return {"ok": True, "cached": False, **out}
    except Exception as e:
        return {"ok": False, "error": str(e)}

@app.get("/api/v2/market/klines")
async def api_v2_market_klines(symbol: str = "BTCUSDT", interval: str = "1h", limit: int = 500):
    try:
        sym = _validate_symbol(symbol)
        itv = _validate_interval(interval)
        limit = int(limit)
        limit = max(10, min(limit, 1000))

        ttl = 20 if itv in ("1m","3m","5m") else 60
        cache_key = f"klines:{sym}:{itv}:{limit}"
        cached = _cache_get(cache_key)
        if cached is not None:
            return {"ok": True, "cached": True, "symbol": sym, "interval": itv, "klines": cached}

        url = "https://api.binance.com/api/v3/klines?" + urlencode({"symbol": sym, "interval": itv, "limit": limit})
        data = await _http_get_json(url, timeout=10.0)
        # Format simplifié
        kl = [{"t": int(x[0]), "o": float(x[1]), "h": float(x[2]), "l": float(x[3]), "c": float(x[4]), "v": float(x[5])} for x in data]
        _cache_set(cache_key, kl, ttl=ttl)
        return {"ok": True, "cached": False, "symbol": sym, "interval": itv, "klines": kl}
    except Exception as e:
        return {"ok": False, "error": str(e)}

@app.get("/api/v2/market/top")
async def api_v2_market_top(
    # New-style params
    vs: str = "usd",
    limit: int = 50,
    spark: int = 1,
    interval: str = "1h",
    # Backward-compatible params used by Opportunity Scanner UI
    vs_currency: str | None = None,
    per_page: int | None = None,
    include_sparkline: bool | None = None,
    price_change_percentage: str | None = None,
):
    """Top coins from CoinGecko (live), with caching + cooldown on rate-limits.

    Compatibility:
      - Accepts both (vs, limit, spark) and legacy (vs_currency, per_page, include_sparkline).
      - Returns item keys expected by Opportunity Scanner: id, symbol, name, price, market_cap, volume,
        change_24h_pct, change_7d_pct, sparkline.
    """
    # normalize inputs (support legacy param names)
    if vs_currency:
        vs = vs_currency
    if per_page is not None:
        limit = per_page
    if include_sparkline is not None:
        spark = 1 if include_sparkline else 0

    vs = (vs or "usd").lower().strip()
    try:
        limit = int(limit)
    except Exception:
        limit = 50
    limit = max(5, min(250, limit))
    spark = 1 if str(spark) == "1" else 0
    interval = (interval or "1h").lower().strip()

    cache_key = ("market_top", vs, limit, spark, interval, price_change_percentage or "")

    # cached response (fresh)
    cached = _cache_get(cache_key)
    if cached is not None:
        # Safety: older cached schemas may contain tuples/strings; normalize/validate.
        try:
            if isinstance(cached, dict) and isinstance((cached.get("items") or cached.get("coins")), list):
                raw_items = cached.get("items") or cached.get("coins") or []
                norm = []
                ok = True
                for c in raw_items:
                    if isinstance(c, dict):
                        norm.append(c)
                    elif isinstance(c, (list, tuple)):
                        sym = str(c[0]).lower() if len(c) > 0 else ""
                        name = str(c[1]) if len(c) > 1 and isinstance(c[1], str) else (sym.upper() if sym else "")
                        nums = [x for x in c[1:] if isinstance(x, (int, float))]
                        price = nums[0] if len(nums) > 0 else None
                        mc = nums[1] if len(nums) > 1 else None
                        chg = nums[2] if len(nums) > 2 else None
                        vol = nums[3] if len(nums) > 3 else None
                        norm.append({"symbol": sym, "name": name, "market_cap": mc, "price": price, "change_24h": chg, "volume_24h": vol})
                    elif isinstance(c, str):
                        sym = c.strip().lower()
                        norm.append({"symbol": sym, "name": sym.upper()})
                    else:
                        ok = False
                        break
                if ok:
                    cached["items"] = norm
                    return cached
        except Exception:
            pass

    import time as _time
    now = _time.time()
    cooldown_until = float(globals().get("_CG_COOLDOWN_UNTIL", 0.0) or 0.0)
    last_ok = globals().get("_CG_LAST_OK_MARKETS")  # full out dict
    last_ok_ts = float(globals().get("_CG_LAST_OK_MARKETS_TS", 0.0) or 0.0)

    # If we're in cooldown, immediately serve last OK (stale) to avoid hammering the API
    if now < cooldown_until and last_ok is not None:
        out = dict(last_ok)
        out["_stale"] = True
        out["_meta"] = {
            "stale": True,
            "reason": "coingecko_cooldown",
            "cooldown_remaining_s": int(max(0, cooldown_until - now)),
            "last_ok_unix": int(last_ok_ts or 0),
        }
        return out

    url = "https://api.coingecko.com/api/v3/coins/markets"
    params = {
        "vs_currency": vs,
        "order": "market_cap_desc",
        "per_page": limit,
        "page": 1,
        "sparkline": "true" if spark else "false",
        "price_change_percentage": price_change_percentage or "24h,7d",
    }

    try:
        data = await _http_get_json(url, params=params, timeout=18)
        items = []
        for c in (data or []):
            sym = (c.get("symbol") or "").upper()
            spr = (c.get("sparkline_in_7d") or {}).get("price") if spark else None
            if spr and interval:
                spr = _cg_resample_prices(spr, interval)
            items.append({
                "id": c.get("id"),
                "symbol": sym,
                "name": c.get("name") or sym,
                "price": c.get("current_price"),
                "market_cap": c.get("market_cap"),
                "volume": c.get("total_volume"),
                "change_24h_pct": c.get("price_change_percentage_24h_in_currency") or c.get("price_change_percentage_24h"),
                "change_7d_pct": c.get("price_change_percentage_7d_in_currency") or c.get("price_change_percentage_7d"),
                "sparkline": spr,
            })

        out = {"ok": True, "vs": vs, "items": items, "_stale": False, "_meta": {"stale": False, "source": "coingecko"}}

        # update last known good
        globals()["_CG_LAST_OK_MARKETS"] = out
        globals()["_CG_LAST_OK_MARKETS_TS"] = now
        globals()["_CG_COOLDOWN_UNTIL"] = 0.0

        # cache fresh (slightly longer to reduce rate-limit risk)
        _cache_set(cache_key, out, ttl=180)
        return out

    except Exception as e:
        # handle rate-limits specifically (from _http_get_json)
        RateLimitError = globals().get("_RateLimitError")
        if RateLimitError and isinstance(e, RateLimitError):
            retry_after = int(getattr(e, "retry_after", 60) or 60)
            globals()["_CG_COOLDOWN_UNTIL"] = now + max(10, min(600, retry_after))

            if last_ok is not None:
                out = dict(last_ok)
                out["_stale"] = True
                out["_meta"] = {
                    "stale": True,
                    "reason": "coingecko_rate_limited",
                    "cooldown_remaining_s": int(max(0, globals()["_CG_COOLDOWN_UNTIL"] - now)),
                    "last_ok_unix": int(last_ok_ts or 0),
                }
                # short cache to stop immediate retries from the UI
                _cache_set(cache_key, out, ttl=30)
                return out

            return {"ok": False, "error": f"Rate limited by CoinGecko. Réessaie dans {retry_after}s.", "_stale": True}

        # generic fallback: serve last OK if available
        if last_ok is not None:
            out = dict(last_ok)
            out["_stale"] = True
            out["_meta"] = {"stale": True, "reason": "coingecko_error", "error": str(e)[:200], "last_ok_unix": int(last_ok_ts or 0)}
            _cache_set(cache_key, out, ttl=30)
            return out

        return {"ok": False, "error": str(e)[:200], "_stale": True}



# ===============================
# Opportunity Scanner WOW — helpers (stable, CoinGecko-sparkline based)
# ===============================

_WOW_SYMBOL_TO_CGID = {}
_WOW_CG_VS = "usd"
_WOW_CG_MARKETS_URL = "https://api.coingecko.com/api/v3/coins/markets"

# Binance 24h ticker cache (to show real last price and Δ24h without abusing rate limits)
_WOW_BINANCE_TICKER_CACHE = {"ts": 0.0, "data": {}}


async def _binance_24h_tickers_map(ttl_seconds: int = 10) -> dict:
    """Return a dict keyed by SYMBOL (e.g. BTCUSDT) with Binance 24h stats.

    Uses a short in-memory TTL cache to reduce calls. If Binance is temporarily
    unavailable, returns the last cached data.
    """
    now = time.time()
    if _WOW_BINANCE_TICKER_CACHE.get("data") and (now - float(_WOW_BINANCE_TICKER_CACHE.get("ts", 0.0)) < ttl_seconds):
        return _WOW_BINANCE_TICKER_CACHE["data"]

    url = "https://api.binance.com/api/v3/ticker/24hr"
    try:
        data = await _fetch_json(url, timeout=10)
        # Binance returns a list of dicts
        out = {}
        if isinstance(data, list):
            for it in data:
                sym = str(it.get("symbol") or "").upper()
                if not sym:
                    continue
                out[sym] = it
        _WOW_BINANCE_TICKER_CACHE["ts"] = now
        _WOW_BINANCE_TICKER_CACHE["data"] = out
        return out
    except Exception:
        # fallback to cached data
        return _WOW_BINANCE_TICKER_CACHE.get("data", {})

def _wow_float(x, default=None):
    try:
        if x is None:
            return default
        return float(x)
    except Exception:
        return default

def _cg_resample_prices(prices, interval: str):
    """Resample CoinGecko hourly sparkline prices into a close-series.

    Notes:
    - CoinGecko sparkline_7d is ~hourly. For 15m, we use linear interpolation (synthetic).
    - Returns a list[float] (close prices).
    """
    if not prices:
        return []
    series = [p for p in (_wow_float(x) for x in prices) if p is not None and math.isfinite(p)]
    if not series:
        return []
    interval = (interval or "1h").strip().lower()

    if interval in ("1h", "60m", "60min", "1hr", "1hour"):
        return series

    if interval in ("15m", "15min", "15"):
        out = []
        for i in range(len(series) - 1):
            a, b = series[i], series[i + 1]
            # 4 segments per hour: 0, 0.25, 0.5, 0.75
            out.extend([a + (b - a) * (k / 4.0) for k in range(4)])
        out.append(series[-1])
        return out

    group = None
    if interval in ("4h", "240m", "4hr", "4hour"):
        group = 4
    elif interval in ("1d", "1day", "24h", "1440m"):
        group = 24

    if not group or group <= 1:
        return series

    out = []
    for i in range(0, len(series), group):
        chunk = series[i:i + group]
        if chunk:
            out.append(chunk[-1])  # close of the grouped candle
    return out

def _wow_rsi(closes, period=14):
    closes = [c for c in closes if c is not None and math.isfinite(c)]
    if len(closes) < period + 2:
        return None
    gains = []
    losses = []
    for i in range(1, period + 1):
        d = closes[-(period + 1 - i)] - closes[-(period + 2 - i)]
        gains.append(max(d, 0.0))
        losses.append(max(-d, 0.0))
    avg_gain = sum(gains) / period
    avg_loss = sum(losses) / period
    if avg_loss == 0:
        return 100.0
    rs = avg_gain / avg_loss
    return 100.0 - (100.0 / (1.0 + rs))

def _wow_slope(closes):
    closes = [c for c in closes if c is not None and math.isfinite(c)]
    n = len(closes)
    if n < 10:
        return 0.0
    # simple linear regression slope on index vs price (normalized)
    x_mean = (n - 1) / 2.0
    y_mean = sum(closes) / n
    num = 0.0
    den = 0.0
    for i, y in enumerate(closes):
        dx = i - x_mean
        num += dx * (y - y_mean)
        den += dx * dx
    if den == 0:
        return 0.0
    slope = num / den
    # normalize by price level to make comparable
    if y_mean:
        slope = slope / y_mean
    return slope

def _opportunity_score(close_series, lookback: int = 240):
    """Return (score:int, tags:list[str])."""
    closes = [c for c in close_series if c is not None and math.isfinite(c)]
    if not closes:
        return 0, ["no-data"]

    closes = closes[-max(10, int(lookback or 240)):]
    n = len(closes)
    if n < 6:
        return 0, ["too-short"]

    last = closes[-1]
    prev = closes[-2] if n >= 2 else last
    ret = (last - prev) / prev if prev else 0.0

    # trend
    slope = _wow_slope(closes)
    trend_score = min(30.0, max(0.0, slope * 4000.0))  # tuned for typical crypto magnitudes

    # breakout: last close above recent range
    window = min(60, n - 1)
    recent = closes[-(window + 1):-1] if window > 0 else closes[:-1]
    hi = max(recent) if recent else last
    lo = min(recent) if recent else last
    breakout = (last - hi) / hi if hi else 0.0
    breakdown = (lo - last) / lo if lo else 0.0

    breakout_score = 0.0
    tags = []
    if breakout > 0.004:  # +0.4%
        breakout_score = min(35.0, breakout * 2500.0)
        tags.append("breakout")
    elif breakdown > 0.004:
        breakout_score = min(20.0, breakdown * 1800.0)
        tags.append("breakdown")

    # reversal: RSI oversold and turning up
    rsi = _wow_rsi(closes, 14)
    reversal_score = 0.0
    if rsi is not None and rsi < 35:
        # if last move is green, call it reversal
        if ret > 0:
            reversal_score = min(25.0, (35.0 - rsi) * 1.2)
            tags.append("reversal")

    # volatility spike (proxy)
    vol_score = min(20.0, abs(ret) * 800.0)
    if abs(ret) > 0.008:
        tags.append("spike")

    score = 10.0 + trend_score + breakout_score + reversal_score + vol_score
    score = max(0.0, min(100.0, score))

    if slope > 0.0008:
        tags.append("trend+")
    elif slope < -0.0008:
        tags.append("trend-")

    # de-dup tags
    tags = list(dict.fromkeys(tags)) if tags else ["neutral"]
    return int(round(score)), tags

def _opportunity_mode(tags):
    t = set((tags or []))
    if "breakout" in t:
        return "Breakout"
    if "reversal" in t:
        return "Reversal"
    if "trend+" in t:
        return "Trend"
    if "breakdown" in t:
        return "Breakdown"
    return "Watch"

async def _cg_coin_id_from_symbol(symbol: str):
    symbol = (symbol or "").strip().lower().replace("usdt", "")
    if not symbol:
        return None
    if symbol in _WOW_SYMBOL_TO_CGID:
        return _WOW_SYMBOL_TO_CGID[symbol]
    # fallback: try to refresh mapping from cached top list
    try:
        top = await api_v2_market_top(limit=250, interval="1h")
        for c in (top.get("items") or []):
            sid = (c.get("symbol") or "").strip().lower()
            cid = c.get("id")
            if sid and cid:
                _WOW_SYMBOL_TO_CGID[sid] = cid
        return _WOW_SYMBOL_TO_CGID.get(symbol)
    except Exception:
        return None

def _wow_closes_to_klines(closes):
    closes = [c for c in closes if c is not None and math.isfinite(c)]
    if len(closes) < 2:
        return []
    out = []
    prev = closes[0]
    for i, c in enumerate(closes):
        o = prev
        h = max(o, c)
        l = min(o, c)
        out.append({"t": i, "o": o, "h": h, "l": l, "c": c})
        prev = c
    return out

async def _fetch_cg_klines(coin_id: str, interval: str = "1h", lookback: int = 240):
    """Fetch OHLC-like candles for one coin using CoinGecko sparkline (stable, low quota)."""
    if not coin_id:
        return []
    params = {
        "vs_currency": _WOW_CG_VS,
        "ids": coin_id,
        "sparkline": "true",
        "price_change_percentage": "24h",
    }
    data = await _fetch_json(_WOW_CG_MARKETS_URL, params=params, timeout=18, cache_ttl=45)
    if not data or not isinstance(data, list):
        return []
    coin = data[0]
    prices = (coin.get("sparkline_in_7d") or {}).get("price") or []
    closes = _cg_resample_prices(prices, interval)
    closes = closes[-max(20, int(lookback or 240)):]
    return _wow_closes_to_klines(closes)



def _wow_bucket_seconds(interval: str) -> int:
    interval = (interval or "1h").strip().lower()
    if interval in ("15m", "15min", "15"):
        return 15 * 60
    if interval in ("1h", "60m", "60min", "1hr", "1hour"):
        return 60 * 60
    if interval in ("4h", "240m", "4hr", "4hour"):
        return 4 * 60 * 60
    if interval in ("1d", "1day", "24h", "1440m"):
        return 24 * 60 * 60
    return 60 * 60

def _wow_days_for_lookback(interval: str, lookback: int) -> int:
    # Pick enough history for the requested lookback, with a safety margin.
    lb = max(30, min(int(lookback or 240), 2000))
    bucket = _wow_bucket_seconds(interval)
    seconds_needed = lb * bucket
    days = int(max(1, min(365, (seconds_needed / 86400.0) * 1.25 + 1)))
    # market_chart "days" supports integers or "max"; keep it bounded for quota/perf.
    return max(1, min(365, days))

async def _fetch_cg_klines_market_chart(coin_id: str, interval: str = "1h", lookback: int = 240):
    """Fetch timestamped close series using CoinGecko market_chart then resample.

    This is more accurate for intraday (15m/1h/4h) than sparkline_7d, and works even when Binance is blocked.
    Returns list[dict] with keys: t (ms epoch), c, close.
    """
    if not coin_id:
        return []
    interval_norm = (interval or "1h").strip().lower()
    lb = max(30, min(int(lookback or 240), 2000))
    days = _wow_days_for_lookback(interval_norm, lb)

    url = f"https://api.coingecko.com/api/v3/coins/{coin_id}/market_chart"
    params = {"vs_currency": _WOW_CG_VS, "days": days}
    data = await _fetch_json(url, params=params, timeout=18, cache_ttl=35)
    prices = (data or {}).get("prices") if isinstance(data, dict) else None
    if not prices or not isinstance(prices, list):
        return []

    bucket = _wow_bucket_seconds(interval_norm)
    # Build buckets with last price (close) per bucket
    buckets = {}
    order = []
    for row in prices:
        try:
            ts_ms = int(row[0])
            px = float(row[1])
            ts_sec = ts_ms // 1000
            b = ts_sec - (ts_sec % bucket)
            if b not in buckets:
                order.append(b)
            buckets[b] = (ts_ms, px)  # keep last
        except Exception:
            continue

    if not order:
        return []
    order.sort()

    kl = []
    for b in order:
        ts_ms, px = buckets[b]
        kl.append({"t": ts_ms, "c": px, "close": px})
    # Keep last lookback candles
    if len(kl) > lb:
        kl = kl[-lb:]
    return kl

def _score_opportunity(klines, interval: str = "1h", lookback: int = 240):
    closes = []
    for k in (klines or []):
        if isinstance(k, dict):
            closes.append(_wow_float(k.get("c") if "c" in k else k.get("close")))
        else:
            closes.append(_wow_float(k))
    closes = [c for c in closes if c is not None and math.isfinite(c)]
    score, tags = _opportunity_score(closes, lookback=lookback)
    mode = _opportunity_mode(tags)
    # French rationale
    bullets = []
    if "breakout" in tags:
        bullets.append("Prix au-dessus du range récent (breakout).")
    if "reversal" in tags:
        bullets.append("RSI bas + bougie verte : possible retournement.")
    if "trend+" in tags:
        bullets.append("Pente positive sur la période : tendance haussière.")
    if "spike" in tags:
        bullets.append("Mouvement rapide (spike) : volatilité élevée.")
    if not bullets:
        bullets.append("Signal neutre : à surveiller.")
    justif = " ".join(bullets)
    return {
        "score": score,
        "mode": mode,
        "tags": tags,
        "justif": justif,
    }

@app.get("/api/v2/opportunity/scan")
async def api_v2_opportunity_scan(
    # New UI params
    universe: str = "",
    interval: str = "1h",
    lookback: int = 240,
    filter: str = "Tous",
    # Backward-compatible params (older UI)
    per_page: int = 30,
    mode: str = "all",
):
    """
    Stable Opportunity Scanner:
    - Uses CoinGecko /coins/markets + sparkline_7d (hourly) to avoid heavy endpoints.
    - Resamples to 15m/1h/4h/1d (15m is synthetic interpolation).
    """
    try:
        # Determine universe size
        u_raw = (universe or "").strip().lower()
        digits = re.findall(r"\d+", u_raw)
        if digits:
            limit = int(digits[0])
        else:
            limit = int(per_page or 30)
        limit = max(5, min(250, limit))

        top = await api_v2_market_top(limit=limit, interval=interval)
        items = top.get("items") or []
        # Normalize items (older cache may contain tuples/strings).
        norm_items = []
        for c in items:
            if isinstance(c, dict):
                norm_items.append(c)
            elif isinstance(c, (list, tuple)):
                sym = str(c[0]).lower() if len(c) > 0 else ""
                name = str(c[1]) if len(c) > 1 and isinstance(c[1], str) else (sym.upper() if sym else "")
                nums = [x for x in c[1:] if isinstance(x, (int, float))]
                price = nums[0] if len(nums) > 0 else None
                mc = nums[1] if len(nums) > 1 else None
                chg = nums[2] if len(nums) > 2 else None
                vol = nums[3] if len(nums) > 3 else None
                norm_items.append({"symbol": sym, "name": name, "market_cap": mc, "price": price, "change_24h": chg, "volume_24h": vol})
            elif isinstance(c, str):
                sym = c.strip().lower()
                norm_items.append({"symbol": sym, "name": sym.upper()})
        items = norm_items

        interval_norm = (interval or "1h").strip().lower()

        # Binance 24h tickers (cached) to populate *real* last price and Δ24h
        tickers_24h = await _binance_24h_tickers_map(ttl_seconds=10)

        # Prefetch Binance closes in parallel for coins where CoinGecko sparkline may be missing
        binance_closes_map = {}
        try:
            import asyncio
            iv = _validate_interval(interval_norm if interval_norm != "24h" else "1d")
            lim = int(lookback or 240)
            lim = max(5, min(lim, 1000))
            need_pairs = []
            for coin in items:
                sym0 = (coin.get("symbol") or "").upper().strip()
                if not sym0:
                    continue
                # If normalized sparkline is missing/too short, mark for Binance
                spr0 = coin.get("sparkline")
                if (not isinstance(spr0, list)) or (len(spr0) < 10):
                    need_pairs.append(_validate_symbol(f"{sym0}USDT"))

            if need_pairs:
                sem = asyncio.Semaphore(10)

                async def _fetch_pair(pair: str):
                    try:
                        ck = f"klines:{pair}:{iv}:{lim}"
                        cached = _cache_get(ck)
                        if cached:
                            closes = [float(x.get("c")) for x in cached if isinstance(x, dict) and x.get("c") is not None]
                            return pair, closes

                        url = f"https://api.binance.com/api/v3/klines?symbol={pair}&interval={iv}&limit={lim}"
                        async with sem:
                            data = await _http_get_json(url, timeout=20)

                        closes = []
                        parsed = []
                        for row in (data or []):
                            try:
                                cclose = float(row[4])
                                cvol = float(row[5])
                                cts = int(row[0])
                                closes.append(cclose)
                                parsed.append({"t": cts, "c": cclose, "v": cvol})
                            except Exception:
                                continue
                        if parsed:
                            _cache_set(ck, parsed, ttl=60)
                        return pair, closes
                    except Exception:
                        return pair, None

                fetched = await asyncio.gather(*[_fetch_pair(p) for p in need_pairs])
                for pair, closes in fetched:
                    if closes:
                        binance_closes_map[pair] = closes
        except Exception:
            binance_closes_map = {}
        meta = top.get("meta") or ""

        # update symbol -> coingecko id mapping
        for c in items:
            sym = (c.get("symbol") or "").strip().lower()
            cid = c.get("id")
            if sym and cid:
                _WOW_SYMBOL_TO_CGID[sym] = cid

        out = []
        # minimum candles depends on interval (1d will be short on 7d sparkline)
        min_candles = 5 if interval_norm in ("1d", "24h", "1day", "1440m") else 25

        for coin in items:
            try:
                sym0 = (coin.get("symbol") or "").upper().strip()
                symbol = (sym0 + "USDT") if sym0 else ""
                closes = coin.get("sparkline") if isinstance(coin.get("sparkline"), list) else []

                if len(closes) < min_candles:
                    # Fallback: use prefetched Binance closes (if CoinGecko sparkline is missing)
                    closes = (binance_closes_map.get(symbol) or [])
                if len(closes) < min_candles:
                    continue

                score, tags = _opportunity_score(closes, lookback=lookback)
                mode_name = _opportunity_mode(tags)

                # optional legacy mode filter
                if mode and mode.lower() not in ("all", "tous", ""):
                    if mode.lower() not in mode_name.lower() and mode.lower() not in ",".join(tags).lower():
                        continue

                # drawdown + volatility (proxy) over lookback window
                w = closes[-max(10, min(int(lookback or 240), len(closes))):]
                peak = max(w) if w else closes[-1]
                dd = ((w[-1] - peak) / peak * 100.0) if peak else 0.0

                # volatility proxy: stdev of returns (in %)
                rets = []
                for i in range(1, len(w)):
                    a, b = w[i-1], w[i]
                    if a:
                        rets.append((b - a) / a)
                if len(rets) >= 2:
                    mu = sum(rets) / len(rets)
                    var = sum((r - mu) ** 2 for r in rets) / (len(rets) - 1)
                    vol = (var ** 0.5) * 100.0
                else:
                    vol = 0.0

                # Prefer Binance 24h ticker for last price + 24h % change when available
                price_val = (coin.get("price") if coin.get("price") is not None else coin.get("current_price"))
                chg_val = (coin.get("change_24h_pct") if coin.get("change_24h_pct") is not None else coin.get("price_change_percentage_24h"))
                src = "coingecko"
                tkr = tickers_24h.get(symbol)
                if isinstance(tkr, dict):
                    try:
                        if tkr.get("lastPrice") is not None:
                            price_val = float(tkr.get("lastPrice"))
                            src = "binance"
                    except Exception:
                        pass
                    try:
                        if tkr.get("priceChangePercent") is not None:
                            chg_val = float(tkr.get("priceChangePercent"))
                            src = "binance"
                    except Exception:
                        pass

                # sanity: 24h percent cannot be below -100
                try:
                    if chg_val is not None and float(chg_val) < -100.0:
                        chg_val = None
                        tags = (tags or []) + ["data_error"]
                except Exception:
                    pass

                out.append({
                    "symbol": symbol,
                    "name": coin.get("name"),
                    "cg_id": coin.get("id"),
                    "mode": mode_name,
                    "score": score,
                    "price": price_val,
                    "change_24h": chg_val,
                    "vol_30d": vol,
                    "dd_30d": dd,
                    # champs attendus par l'UI WOW
                    "pct24h": (chg_val / 100.0) if isinstance(chg_val, (int, float)) else 0.0,
                    "vol_rel": float(vol) if isinstance(vol, (int, float)) else 0.0,  # en %
                    "dd": float(dd) if isinstance(dd, (int, float)) else 0.0,          # en %
                    "tags": tags,
                    "src": src,
                })
            except Exception:
                continue

        # filter (new UI)
        f = (filter or "").strip().lower()
        if f and f not in ("tous", "all"):
            out = [x for x in out if (f in (x.get("mode") or "").lower()) or (f in ",".join(x.get("tags") or []).lower())]

        # sort by score
        out.sort(key=lambda x: x.get("score", 0), reverse=True)

        return {
            "ok": True,
            "meta": meta,
            "items": out[:200],
            "count": len(out),
            "interval": interval_norm,
            "limit": limit,
            "updated_at": dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        }
    except Exception as e:
        # Never hard-crash the UI: return a JSON payload (HTTP 200) with the error.
        return {
            "ok": False,
            "error": str(e),
            "items": [],
            "count": 0,
            "interval": (interval or "1h"),
            "limit": int(per_page or 30),
            "updated_at": dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        }


# Compat: the UI uses POST (JSON body). Keep GET for direct URL testing.



# =========================
# AI Market Regime (v2 API)
# =========================

_MARKET_REGIME_CACHE = {}  # key -> {"ts": float, "payload": dict}
_MARKET_REGIME_TTL_SEC = 25

def _clamp(v: float, lo: float, hi: float) -> float:
    try:
        v = float(v)
    except Exception:
        return lo
    return max(lo, min(hi, v))

def _std(values):
    vals = [float(x) for x in values if x is not None]
    n = len(vals)
    if n < 2:
        return 0.0
    mu = sum(vals) / n
    var = sum((x - mu) ** 2 for x in vals) / (n - 1)
    return var ** 0.5

def _pct_change(a: float, b: float) -> float:
    try:
        a = float(a); b = float(b)
        if b == 0:
            return 0.0
        return (a / b - 1.0) * 100.0
    except Exception:
        return 0.0

def _safe_float(x, default=0.0):
    try:
        return float(x)
    except Exception:
        return float(default)

async def _compute_market_regime(interval: str = "4h", lookback: int = 240) -> dict:
    """
    Compute a market regime using live exchange data (Binance) + global market context (CoinGecko).
    Returns a JSON-serializable payload used by /ai-market-regime.
    """
    interval = (interval or "4h").lower().strip()
    if interval not in {"1h", "4h", "1d"}:
        interval = "4h"

    try:
        lookback = int(lookback)
    except Exception:
        lookback = 240
    lookback = max(120, min(lookback, 1000))

    # --- Fetch series ---
    btc_kl, src_btc = await _get_spot_klines("BTCUSDT", interval, limit=lookback)
    eth_kl, _src_eth = await _get_spot_klines("ETHUSDT", interval, limit=lookback)
    ethbtc_kl, src_ethbtc = await _get_spot_klines("ETHBTC", interval, limit=lookback)
    if not btc_kl or len(btc_kl) < 80:
        raise RuntimeError("Données Binance insuffisantes pour calculer le régime (BTC).")

    btc_close = [float(k[4]) for k in btc_kl]
    eth_close = [float(k[4]) for k in eth_kl] if eth_kl else []
    ethbtc_close = [float(k[4]) for k in ethbtc_kl] if ethbtc_kl else []

    # --- Indicators ---
    ema20 = _ema(btc_close, 20)
    ema50 = _ema(btc_close, 50)
    ema200 = _ema(btc_close, 200) if len(btc_close) >= 200 else _ema(btc_close, max(80, len(btc_close)//2))

    px = btc_close[-1]
    trend_vs_ema50 = _pct_change(px, ema50)
    trend_vs_ema200 = _pct_change(px, ema200)

    # momentum over last ~10 candles (timeframe dependent)
    mom_n = 10 if len(btc_close) > 20 else max(3, len(btc_close)//3)
    momentum = _pct_change(btc_close[-1], btc_close[-mom_n])

    # volatility: std of returns (last 30 candles)
    rets = []
    for i in range(-31, -1):
        if abs(i) <= len(btc_close):
            prev = btc_close[i-1]
            cur = btc_close[i]
            if prev != 0:
                rets.append((cur/prev - 1.0) * 100.0)
    vol = _std(rets)  # in %

    # alt strength proxy: ETHBTC momentum
    alt_momentum = 0.0
    if len(ethbtc_close) >= mom_n + 2:
        alt_momentum = _pct_change(ethbtc_close[-1], ethbtc_close[-mom_n])

    # --- Global context (CoinGecko) ---
    cg = await _fetch_json("https://api.coingecko.com/api/v3/global", timeout=10)
    cg_data = (cg or {}).get("data") or {}
    total_mcap = _safe_float((cg_data.get("total_market_cap") or {}).get("usd"), 0.0)
    mcap_chg_24h = _safe_float(cg_data.get("market_cap_change_percentage_24h_usd"), 0.0)
    dom = cg_data.get("market_cap_percentage") or {}
    btc_dom = _safe_float(dom.get("btc"), 0.0)
    eth_dom = _safe_float(dom.get("eth"), 0.0)

    # --- Scoring (AI-like heuristic; transparent factors) ---
    # Trend
    s_trend = _clamp(trend_vs_ema50 * 4.0, -40, 40)
    s_cross = 15.0 if ema20 > ema50 else -15.0
    s_mom = _clamp(momentum * 2.0, -20, 20)

    # Volatility: lower vol = better risk-on. Typical intraday vol range ~0.5-3%
    s_vol = _clamp((1.6 - vol) * 12.0, -20, 20)

    # Alt strength: ETH/BTC up => risk-on (alts bid)
    s_alt = _clamp(alt_momentum * 250.0, -25, 25)

    # Dominance context: higher BTC dominance often = risk-off; use deviation vs 50% pivot softly
    s_dom = _clamp((50.0 - btc_dom) * 0.8, -15, 15)

    raw_score = s_trend + s_cross + s_mom + s_vol + s_alt + s_dom
    score = float(_clamp(raw_score, -100, 100))

    # Agreement/confidence
    factor_signs = [
        1 if s_trend > 0 else (-1 if s_trend < 0 else 0),
        1 if s_cross > 0 else (-1 if s_cross < 0 else 0),
        1 if s_mom > 0 else (-1 if s_mom < 0 else 0),
        1 if s_vol > 0 else (-1 if s_vol < 0 else 0),
        1 if s_alt > 0 else (-1 if s_alt < 0 else 0),
        1 if s_dom > 0 else (-1 if s_dom < 0 else 0),
    ]
    pos = sum(1 for x in factor_signs if x > 0)
    neg = sum(1 for x in factor_signs if x < 0)
    agreement = abs(pos - neg) / 6.0  # 0..1
    conf = int(_clamp((abs(score) / 100.0) * 70.0 + agreement * 30.0, 5, 95))

    # Labels
    if score >= 60:
        regime = "RISK-ON (BULL)"
        vibe = "🚀"
        badge = "success"
    elif score >= 20:
        regime = "RISK-ON"
        vibe = "🟢"
        badge = "success"
    elif score <= -60:
        regime = "RISK-OFF (DEFENSIF)"
        vibe = "🧊"
        badge = "danger"
    elif score <= -20:
        regime = "RISK-OFF"
        vibe = "🔴"
        badge = "danger"
    else:
        regime = "NEUTRE"
        vibe = "🟡"
        badge = "warning"

    # Sparkline (BTC close) - use last 80 pts
    sp = _sparkline_svg(btc_close[-80:], w=260, h=56, stroke="rgba(255,255,255,0.85)")
    sp_alt = _sparkline_svg(ethbtc_close[-80:], w=260, h=56, stroke="rgba(176,220,255,0.9)") if len(ethbtc_close) >= 40 else ""

    # Rationale bullets
    reasons = []
    reasons.append(f"BTC vs EMA50: {trend_vs_ema50:+.2f}%")
    reasons.append(f"Momentum ({mom_n} bougies): {momentum:+.2f}%")
    reasons.append(f"Volatilité (≈30 bougies): {vol:.2f}%")
    if len(ethbtc_close) >= mom_n + 2:
        reasons.append(f"Force ALT (ETH/BTC): {alt_momentum:+.3f}%")
    reasons.append(f"Dominance BTC: {btc_dom:.1f}% (ETH: {eth_dom:.1f}%)")
    reasons.append(f"Market cap 24h: {mcap_chg_24h:+.2f}%")

    factors = [
        {"name": "Trend (EMA50)", "value": trend_vs_ema50, "score": s_trend, "hint": "Prix vs EMA50"},
        {"name": "Cross (EMA20/50)", "value": 1 if ema20 > ema50 else -1, "score": s_cross, "hint": "EMA20 au-dessus / en-dessous"},
        {"name": "Momentum", "value": momentum, "score": s_mom, "hint": f"Variation sur {mom_n} bougies"},
        {"name": "Volatilité", "value": vol, "score": s_vol, "hint": "Plus bas = mieux (risk-on)"},
        {"name": "Force ALT", "value": alt_momentum, "score": s_alt, "hint": "ETH/BTC monte = alts bid"},
        {"name": "Dominance", "value": btc_dom, "score": s_dom, "hint": "Dominance BTC élevée = plus défensif"},
    ]

    now_iso = dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z"
    payload = {
        "ok": True,
        "interval": interval,
        "lookback": lookback,
        "updated_at": now_iso,
        "regime": regime,
        "badge": badge,
        "vibe": vibe,
        "score": round(score, 1),
        "confidence": conf,
        "btc_price": px,
        "total_mcap_usd": total_mcap,
        "mcap_change_24h_pct": round(mcap_chg_24h, 2),
        "btc_dominance_pct": round(btc_dom, 2),
        "eth_dominance_pct": round(eth_dom, 2),
        "spark_btc_svg": sp,
        "spark_alt_svg": sp_alt,
        "reasons": reasons,
        "factors": factors,
        "notes": [
            "Sources: Binance (prix/klines), CoinGecko (market cap & dominance).",
            "Ce score est un modèle heuristique (IA) pour donner une lecture rapide — pas un conseil financier."
        ],
    }
    return payload

@app.get("/api/v2/market-regime", response_class=JSONResponse)
async def api_v2_market_regime(interval: str = "4h", lookback: int = 240):
    """
    Live market regime endpoint used by /ai-market-regime.
    Cached briefly to avoid rate-limits.
    """
    try:
        key = f"{(interval or '4h').lower()}|{int(lookback) if str(lookback).isdigit() else 240}"
    except Exception:
        key = "4h|240"

    now = time.time()
    cached = _MARKET_REGIME_CACHE.get(key)
    if cached and (now - cached.get("ts", 0)) < _MARKET_REGIME_TTL_SEC:
        return JSONResponse(cached["payload"])

    try:
        payload = await _compute_market_regime(interval=interval, lookback=lookback)
    except Exception as e:
        # Si live fetch échoue, on essaie de servir la dernière valeur OK (cache) pour éviter une page "cassée".
        cached = _MARKET_REGIME_CACHE.get(key) if isinstance(_MARKET_REGIME_CACHE, dict) else None
        if cached and isinstance(cached, dict) and isinstance(cached.get("payload"), dict) and cached["payload"].get("ok") is True:
            payload = dict(cached["payload"])
            payload["degraded"] = True
            payload["warning"] = f"Live fetch failed: {str(e)[:180]}"
            payload["updated_at"] = dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z"
            payload.setdefault("message", "Mode cache (dernier calcul disponible).")
        else:
            payload = {
                "ok": False,
                "error": "market_regime_failed",
                "message": str(e)[:300],
                "interval": (interval or "4h"),
                "lookback": lookback,
                "updated_at": dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
            }

    _MARKET_REGIME_CACHE[key] = {"ts": now, "payload": payload}
    return JSONResponse(payload)


@app.post("/api/v2/opportunity/scan")
async def api_v2_opportunity_scan_post(body: dict = Body(default={} )):
    try:
        # Accept both numeric and string values safely
        universe = int((body.get("universe") if isinstance(body, dict) else None) or 30)
        interval = str((body.get("interval") if isinstance(body, dict) else None) or "1h")
        lookback = int((body.get("lookback") if isinstance(body, dict) else None) or 240)
        filter_mode = str((body.get("filter") if isinstance(body, dict) else None) or "all")
        return await api_v2_opportunity_scan(
            universe=universe,
            interval=interval,
            lookback=lookback,
            filter=filter_mode,
        )
    except Exception as e:
        # Never hard-crash the UI: return a JSON payload (HTTP 200) with the error.
        return {
            "ok": False,
            "error": str(e),
            "items": [],
            "count": 0,
            "interval": (interval or "1h"),
            "limit": int(per_page or 30),
            "updated_at": dt.datetime.utcnow().replace(microsecond=0).isoformat() + "Z",
        }


@app.get("/api/v2/opportunity/detail")
async def api_v2_opportunity_detail(
    symbol: str,
    interval: str = "1h",
    lookback: int = 240,
    mode: str = "all",
    cg_id: str = "",
):
    """Analyse détaillée (graph + justification IA) pour un symbole.

    Objectif:
    - Fonctionne pour 15m / 1h / 4h / 1d
    - Utilise CoinGecko (market_chart) pour des séries intraday plus fiables.
    - Fallback sur sparkline_7d si CoinGecko renvoie trop peu de données.

    Retour JSON:
      { ok, symbol, price, mode, score, rationale, details, series:[{t, close}] }
    """
    try:
        sym = (symbol or "").strip().upper()
        if not sym:
            return {"ok": False, "error": "Missing symbol"}

        interval_norm = str(interval or "1h").strip().lower()
        lb = max(30, min(int(lookback or 240), 2000))

        # 1) Résoudre CoinGecko ID (priorité à cg_id envoyé par l'UI)
        cid = (cg_id or "").strip()
        if not cid:
            if not isinstance(globals().get("_WOW_SYMBOL_TO_CGID"), dict):
                globals()["_WOW_SYMBOL_TO_CGID"] = {}
            cid = globals()["_WOW_SYMBOL_TO_CGID"].get(sym)
            if not cid:
                # Try infer from base symbol (e.g., BTCUSDT -> btc)
                base = sym
                for q in ("USDT", "USD", "BUSD", "USDC"):
                    if base.endswith(q):
                        base = base[:-len(q)]
                        break
                cid = await _cg_coin_id_from_symbol(base)
                if cid:
                    globals()["_WOW_SYMBOL_TO_CGID"][sym] = cid

        if not cid:
            return {"ok": False, "error": f"Unknown symbol: {sym}"}

        # 2) Fetch series (market_chart -> resample) then fallback on sparkline
        klines = await _fetch_cg_klines_market_chart(cid, interval_norm, lb)
        src = "coingecko_market_chart"
        if not klines or len(klines) < 10:
            klines = await _fetch_cg_klines(cid, interval_norm, lb)
            src = "coingecko_sparkline_7d"

        if not klines or len(klines) < 10:
            return {"ok": False, "error": "Not enough data"}

        closes = []
        series = []
        for k in klines:
            try:
                c = _wow_float(k.get("c") if isinstance(k, dict) else None)
                t = k.get("t") if isinstance(k, dict) else None
                if c is None:
                    continue
                closes.append(float(c))
                series.append({"t": t, "close": float(c)})
            except Exception:
                continue

        if len(closes) < 10:
            return {"ok": False, "error": "Not enough data"}

        price = closes[-1]

        # 3) Score + tags (mêmes heuristiques que la liste)
        scored = _score_opportunity(klines, interval=interval_norm, lookback=lb) if callable(globals().get("_score_opportunity")) else None
        if isinstance(scored, dict):
            score = int(scored.get("score") or 0)
            mode2 = scored.get("mode") or "-"
            tags = scored.get("tags") or []
            justif = scored.get("justif") or ""
        else:
            score, tags = _opportunity_score(closes, lookback=lb)
            mode2 = _opportunity_mode(tags)
            justif = ""

        # 4) Extra metrics (DD + vol) for "details"
        dd_pct = 0.0
        vol_std = 0.0
        try:
            w = closes[-min(len(closes), lb):]
            peak = w[0]
            max_dd = 0.0
            for c in w:
                if c > peak:
                    peak = c
                dd = (c / peak - 1.0) * 100.0
                if dd < max_dd:
                    max_dd = dd
            dd_pct = float(max_dd)
            rets = [(w[i] / w[i-1] - 1.0) for i in range(1, len(w)) if w[i-1]]
            if rets:
                mean = sum(rets) / len(rets)
                var = sum((r - mean) ** 2 for r in rets) / len(rets)
                vol_std = float(var ** 0.5)
        except Exception:
            dd_pct = 0.0
            vol_std = 0.0

        tag_txt = ", ".join(tags) if tags else "aucun signal fort"
        rationale = (
            f"Mode détecté: {mode2}. "
            f"Tags: {tag_txt}. "
            + (justif if justif else "Interprétation: ces tags sont des heuristiques (pas une certitude).")
        )

        details = (
            f"Source: {src}. Intervalle: {interval_norm}. Lookback: {lb}. "
            f"Score: {score}/100. "
            f"Drawdown approx: {dd_pct:.1f}%. Volatilité (std ret): {vol_std:.4f}."
        )

        return {
            "ok": True,
            "symbol": sym,
            "price": price,
            "mode": mode2,
            "score": score,
            "rationale": rationale,
            "details": details,
            "series": series,
        }
    except Exception as e:
        return {"ok": False, "error": str(e)}

