def init_ebooks_table():
    """Crée les tables ebooks et contact_messages"""
    try:
        conn = get_db_connection()
        c = conn.cursor()
        
        # Table ebooks
        if DB_CONFIG["type"] == "postgres":
            c.execute("""CREATE TABLE IF NOT EXISTS ebooks (
                id SERIAL PRIMARY KEY,
                title TEXT NOT NULL,
                description TEXT,
                filename TEXT NOT NULL,
                file_size INTEGER,
                min_plan TEXT DEFAULT 'Free',
                downloads INTEGER DEFAULT 0,
                active BOOLEAN DEFAULT TRUE,
                created_at TIMESTAMP DEFAULT NOW()
            )""")
        else:
            c.execute("""CREATE TABLE IF NOT EXISTS ebooks (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title TEXT NOT NULL,
                description TEXT,
                filename TEXT NOT NULL,
                file_size INTEGER,
                min_plan TEXT DEFAULT 'Free',
                downloads INTEGER DEFAULT 0,
                active INTEGER DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )""")
        
        # Table contact_messages
        if DB_CONFIG["type"] == "postgres":
            c.execute("""CREATE TABLE IF NOT EXISTS contact_messages (
                id SERIAL PRIMARY KEY,
                name TEXT NOT NULL,
                email TEXT NOT NULL,
                subject TEXT,
                page TEXT,
                message TEXT NOT NULL,
                user_id TEXT,
                status TEXT DEFAULT 'unread',
                created_at TIMESTAMP DEFAULT NOW()
            )""")
        else:
            c.execute("""CREATE TABLE IF NOT EXISTS contact_messages (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                email TEXT NOT NULL,
                subject TEXT,
                page TEXT,
                message TEXT NOT NULL,
                user_id TEXT,
                status TEXT DEFAULT 'unread',
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
            )""")
        

        # Migration: ajouter la colonne 'page' si elle n'existe pas (anciens déploiements)
        try:
            if DB_CONFIG["type"] == "postgres":
                c.execute("ALTER TABLE contact_messages ADD COLUMN IF NOT EXISTS page TEXT")
            else:
                c.execute("ALTER TABLE contact_messages ADD COLUMN page TEXT")
        except Exception:
            pass

        conn.commit()
        conn.close()
        print(f"✅ Tables ebooks et contact créées ({DB_CONFIG['type']})")
        return True
    except Exception as e:
        print(f"❌ Init ebooks/contact: {e}")
        return False



