# Dterminer le rpertoire de donnes au dmarrage

def _is_writable_dir(path: str) -> bool:
    """Retourne True si le répertoire est accessible en écriture."""
    try:
        os.makedirs(path, exist_ok=True)
        test_file = os.path.join(path, ".write_test")
        with open(test_file, "w", encoding="utf-8") as f:
            f.write("ok")
        os.remove(test_file)
        return True
    except Exception:
        return False


def get_data_directory() -> str:
    """Choisit un répertoire persistant si possible, sinon fallback sur /tmp.

    - DB_DIR (env) prioritaire
    - /app/data si writable (Railway/Render selon mounts)
    - /tmp/ai_trader en dernier recours
    """
    env_dir = (os.getenv("DB_DIR") or "").strip()
    candidates = []
    if env_dir:
        candidates.append(env_dir)
    candidates.extend([
        "/app/data",
        "/data",
        "/tmp/ai_trader",
    ])
    for d in candidates:
        if d and _is_writable_dir(d):
            return d
    return "/tmp/ai_trader"

DATA_DIR = get_data_directory()

#  FICHIER DE PERSISTANCE DES TRADES
TRADES_FILE = f"{DATA_DIR}/trades_database.json"

# --- Robustesse: si le fichier existe mais n'est pas inscriptible, basculer vers /tmp
def _ensure_writable_trades_file():
    global TRADES_FILE
    try:
        os.makedirs(os.path.dirname(TRADES_FILE), exist_ok=True)
        # Si le fichier existe mais n'est pas writable (ex: volume mont avec mauvais owner)
        if os.path.exists(TRADES_FILE) and not os.access(TRADES_FILE, os.W_OK):
            raise PermissionError(f'File not writable: {TRADES_FILE}')
        # Test d'criture (append)
        with open(TRADES_FILE, 'a', encoding='utf-8'):
            pass
    except Exception as e:
        fallback_dir = '/tmp/ai_trader'
        os.makedirs(fallback_dir, exist_ok=True)
        TRADES_FILE = os.path.join(fallback_dir, 'trades_database.json')
        try:
            with open(TRADES_FILE, 'a', encoding='utf-8'):
                pass
            print(f'⚠️ TRADES_FILE non inscriptible, fallback → {TRADES_FILE} ({e})')
        except Exception as e2:
            print(f'❌ Impossible de configurer TRADES_FILE fallback: {e2}')

_ensure_writable_trades_file()


# ==========================
# Trades persistence (JSON)
# ==========================
# NOTE: Le projet utilise SQLite pour les tables "trades", mais plusieurs
# routes/moniteurs utilisent encore une liste mémoire `trades_db` + un fichier JSON.
# Ces helpers évitent les crashs au démarrage et gardent la compatibilité.

trades_db = []  # liste de dicts (trades)

def load_trades_from_file():
    """Charge les trades depuis le JSON (tolère fichier absent ou vide)."""
    global trades_db
    if not os.path.exists(TRADES_FILE):
        print(f"⚠️ Aucun fichier trades JSON trouvé: {TRADES_FILE}")
        trades_db = []
        return

    try:
        # Si le fichier est vide (0 octet / espaces), json.load() lève une erreur.
        with open(TRADES_FILE, "r", encoding="utf-8") as f:
            raw = f.read()

        if not raw or not raw.strip():
            trades_db = []
            return

        trades_db = json.loads(raw)

        # Normaliser (au cas où le JSON ne serait pas une liste)
        if not isinstance(trades_db, list):
            trades_db = []

    except json.JSONDecodeError as e:
        print(f"⚠️ Trades JSON invalide (on repart vide): {e}")
        trades_db = []
    except Exception as e:
        print(f"⚠️ Impossible de charger les trades depuis JSON: {e}")
        trades_db = []

def save_trades_to_file():
    """Sauvegarde `trades_db` vers TRADES_FILE (JSON) en écriture atomique."""
    global trades_db, TRADES_FILE
    try:
        _ensure_writable_trades_file()
        if not TRADES_FILE:
            return
        os.makedirs(os.path.dirname(TRADES_FILE), exist_ok=True)
        tmp_path = TRADES_FILE + ".tmp"
        with open(tmp_path, "w", encoding="utf-8") as f:
            json.dump(trades_db, f, ensure_ascii=False, indent=2, default=str)
        os.replace(tmp_path, TRADES_FILE)
    except Exception as e:
        print(f"⚠️ Impossible de sauvegarder les trades vers JSON: {e}")

