# Fonctions de compatibilit pour le code existant
def hash_password(password: str) -> str:
    """Hasher un mot de passe"""
    return hashlib.sha256(password.encode()).hexdigest()

def verify_user(username: str, password: str) -> bool:
    """Compat: utilise la même base users que le reste du site (ai_trader.db)."""
    return db_manager.verify_user(username, password)

def generate_temp_password(length: int = 12) -> str:
    """Génère un mot de passe temporaire robuste (admin reset).
    - Évite les caractères ambigus (O/0, l/1, etc.)
    - Assure une complexité minimale (maj/min/chiffre/symbole)
    """
    try:
        length = int(length)
    except Exception:
        length = 12
    if length < 8:
        length = 8

    upper = "ABCDEFGHJKLMNPQRSTUVWXYZ"
    lower = "abcdefghijkmnopqrstuvwxyz"
    digits = "23456789"
    symbols = "!@#$%&*?"
    pool = upper + lower + digits + symbols

    # garantir au moins 1 de chaque
    pw = [_secrets.choice(upper), _secrets.choice(lower), _secrets.choice(digits), _secrets.choice(symbols)]
    pw += [_secrets.choice(pool) for _ in range(length - len(pw))]
    random.SystemRandom().shuffle(pw)
    return "".join(pw)


def create_session(username: str, user_info: dict = None) -> str:
    """Créer une session pour un utilisateur avec infos d'abonnement"""
    import secrets
    token = secrets.token_urlsafe(32)
    
    if user_info:
        # Stocker toutes les infos de l'utilisateur
        active_sessions[token] = user_info
    else:
        # Rcuprer les infos depuis la DB
        user_data = db_manager.get_user_info(username)
        active_sessions[token] = user_data
    
    return token

def get_user_from_token(token: Optional[str]):
    """Récupérer l'utilisateur depuis un token de session.

    Normalise les anciens formats : si active_sessions[token] est une string (ex: "admin"),
    on la convertit en dict {"username": "..."} afin que les middlewares puissent lire username/role.
    """
    if not token:
        return None

    user_data = active_sessions.get(token)
    if not user_data:
        return None

    # Ancien format: juste un username en string
    if isinstance(user_data, str):
        uname = user_data.strip()
        user_dict = {"username": uname}
        # Enrichir avec le rôle depuis la DB si possible
        try:
            role = db_manager.get_user_role(uname)
            if role:
                user_dict["role"] = role
        except Exception:
            pass
        return user_dict

    # Format dict: s'assurer qu'on a un username et (si possible) un role
    if isinstance(user_data, dict):
        uname = (user_data.get("username") or user_data.get("email") or "").strip()
        if uname and not user_data.get("role"):
            try:
                role = db_manager.get_user_role(uname)
                if role:
                    user_data["role"] = role
            except Exception:
                pass
        return user_data

    


def get_current_user(session_token: Optional[str] = Cookie(None)) -> Optional[str]:
    """Dépendance FastAPI (Cookie injection) -> retourne le username ou None."""
    if not session_token:
        return None
    return get_user_from_token(session_token)


def get_current_user_from_request(request: Request) -> Optional[str]:
    """Helper pour les appels 'manuels' avec Request (pas l'injection FastAPI)."""
    token = request.cookies.get("session_token")
    if not token:
        return None
    return get_user_from_token(token)



def normalize_username(value: str) -> str:
    """Normalise un identifiant utilisateur (username/email) pour les comparaisons."""
    try:
        return (value or "").strip().lower()
    except Exception:
        return ""




# ---------------------------------------------------------------------------
# Compat helpers (some IA pages call these; keep them stable)
# ---------------------------------------------------------------------------
def is_logged_in(request) -> bool:
    """Vrai si un token de session valide est présent et reconnu."""
    user = get_user_from_request(request)
    if not user:
        return False
    return bool(user.get("username") or user.get("email"))

def get_user_effective_plan(request: Request) -> str:
    """Best-effort plan resolution used for debug/UI. Admins are treated as full access."""
    try:
        u = get_user_from_request(request) or {}
        if isinstance(u, dict) and u.get("is_admin"):
            return "elite"
        # Try stored plan in session/db
        if isinstance(u, dict):
            p = (u.get("plan") or u.get("subscription_plan") or u.get("user_plan") or "").strip().lower()
            if p:
                return p
            uname = (u.get("username") or "").strip()
            email = (u.get("email") or "").strip()
        else:
            uname, email = "", ""
        if not uname and hasattr(request, "session") and request.session:
            uname = (request.session.get("username") or "").strip()
            email = (request.session.get("email") or "").strip()
        # get_user_plan exists elsewhere in this file
        if uname or email:
            try:
                p = (get_user_plan(uname or email) or "").strip().lower()
                if p:
                    return p
            except Exception:
                pass
    except Exception:
        pass
    return "free"

def get_user_plan(username: str) -> str:
    """Retourne le plan (free/premium/advanced/pro/elite) pour un username OU un dict user.

    - Si l'utilisateur n'est pas loggé ou si la DB n'est pas accessible: retourne 'free'.
    - Supporte les appels existants qui passent un dict (user_info).
    """
    try:
        # Support legacy: get_user_plan(user_dict)
        if isinstance(username, dict):
            user = username
            uname = (user.get("username") or "").strip()
        else:
            uname = (username or "").strip()

        if not uname:
            return "free"

        db_path = os.getenv("DB_PATH", "/app/data/ai_trader.db")
        conn = sqlite3.connect(db_path)
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        cur.execute("SELECT plan FROM users WHERE username = ? LIMIT 1", (uname,))
        row = cur.fetchone()
        conn.close()

        plan = (row["plan"] if row else None) or "free"
        plan = str(plan).strip().lower()
        # normalisation
        if plan in ("gratuit", "free"):
            return "free"
        if plan in ("premium",):
            return "premium"
        if plan in ("advanced", "avance", "avancé"):
            return "advanced"
        if plan in ("pro",):
            return "pro"
        if plan in ("elite", "élit", "élite"):
            return "elite"
        return plan or "free"
    except Exception as e:
        print(f"⚠️ get_user_plan: fallback 'free' (err={e})")
        return "free"

def html_doc(title: str, body_html: str, extra_head: str = "") -> str:
    """
    Construit un document HTML complet.
    Utilisé pour les pages "placeholder" (ex: accès refusé) afin d'éviter les NameError.
    """
    safe_title = (title or "CryptoIA").replace("<", "&lt;").replace(">", "&gt;")
    return f"""<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>{safe_title}</title>
  {extra_head or ""}
  <style>
    :root {{ color-scheme: dark; }}
    body {{
      margin: 0;
      font-family: -apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Arial,sans-serif;
      background: #0b1220;
      color: #e7eefc;
    }}
    .container {{ max-width: 980px; margin: 40px auto; padding: 0 16px; }}
    .card {{
      background: rgba(255,255,255,0.04);
      border: 1px solid rgba(255,255,255,0.10);
      border-radius: 14px;
      padding: 18px;
      box-shadow: 0 10px 30px rgba(0,0,0,0.35);
    }}
    a.btn {{
      display: inline-block;
      margin-top: 12px;
      background: #2563eb;
      color: #fff !important;
      text-decoration: none;
      padding: 10px 14px;
      border-radius: 10px;
      font-weight: 700;
    }}
    a.btn:hover {{ filter: brightness(1.05); }}
  </style>
</head>
<body>
{body_html}
</body>
</html>"""


def get_logged_user(request: Request) -> Optional[dict]:
    """Retourne le dict utilisateur de la session, ou None si pas connecté."""
    token = request.cookies.get("session_token")
    if not token:
        return None
    user = get_user_from_token(token)
    if not user:
        return None

    # Garantir un champ username (string)
    u = user.get("username") or user.get("email") or ""
    if isinstance(u, dict):
        u = u.get("username") or u.get("email") or ""
    user["username"] = str(u).strip()

    # Normaliser un champ role si présent
    r = user.get("role") or user.get("user_role") or ""
    if r:
        user["role"] = str(r).strip().lower()

    return user



def get_user_role(username: str) -> str:
    """Compat: rôle depuis ai_trader.db."""
    return db_manager.get_user_role(username)

def get_user_permission(username: str, route: str) -> bool:
    """
    True si l'utilisateur a une permission explicite pour une route.

    ✅ Compatible avec anciennes valeurs stockées en DB (avec "/" devant).
    """
    try:
        username = normalize_username(username or "")
        if not username:
            return False

        # Normaliser la route pour être cohérent partout
        route_key = normalize_route_key(route or "")
        if not route_key:
            return False

        # Compat: certaines entrées DB ont été enregistrées avec "/" (ex: "/dashboard")
        candidates = (route_key, f"/{route_key}")

        conn = db_manager.get_connection()
        cur = conn.cursor()

        if getattr(db_manager, "use_postgresql", False):
            cur.execute(
                """
                SELECT 1
                FROM user_permissions
                WHERE LOWER(username)=LOWER(%s)
                  AND (route=%s OR route=%s)
                LIMIT 1
                """,
                (username, candidates[0], candidates[1]),
            )
        else:
            cur.execute(
                """
                SELECT 1
                FROM user_permissions
                WHERE LOWER(username)=LOWER(?)
                  AND (route=? OR route=?)
                LIMIT 1
                """,
                (username, candidates[0], candidates[1]),
            )

        row = cur.fetchone()
        try:
            conn.close()
        except Exception:
            pass
        return row is not None
    except Exception:
        return False

def require_auth(session_token: Optional[str] = Cookie(None)):
    """Dépendance FastAPI pour exiger une authentification"""
    user = get_user_from_token(session_token)
    if not user:
        raise HTTPException(status_code=401, detail="Non authentifié")
    return user

# 
#  SYSTME DE PERMISSIONS - CONFIGURATION
# 

# Routes TOUJOURS accessibles (sans authentification)
PUBLIC_ROUTES = ["/", "/login", "/register", "/logout", "/health", "/tv-webhook"]

# Routes MINIMUM donnes  TOUS les utilisateurs par dfaut
DEFAULT_USER_PERMISSIONS = [
    "/dashboard",            # Dashboard (gratuit après login)
    "/mon-compte",           # Gestion compte / abonnement
]


def require_admin(user=Depends(require_auth)):
    """Dependency: require an authenticated *admin* user.

    Accepte uniquement les utilisateurs avec role 'admin' (ou un flag is_admin vrai).
    """
    # If require_auth returned a redirect/response, just pass it through (FastAPI will handle).
    # But typically it raises HTTPException instead.
    try:
        username = user.get("username") if isinstance(user, dict) else getattr(user, "username", None)
        role = user.get("role") if isinstance(user, dict) else getattr(user, "role", None)
        is_admin = user.get("is_admin") if isinstance(user, dict) else getattr(user, "is_admin", False)

        if (role == "admin") or bool(is_admin):
            return user

        # Fallback: check DB role if available
        try:
            if "db_manager" in globals() and username:
                info = db_manager.get_user_info(username)
                if info and (info.get("role") == "admin" or info.get("is_admin") == 1):
                    return user
        except Exception:
            pass
    except Exception:
        pass

    raise HTTPException(status_code=403, detail="Accès réservé aux administrateurs")

def give_default_permissions(username: str) -> bool:
    """
    🎁 Attribue les permissions par défaut à un nouvel utilisateur
    
    Donne automatiquement accès à:
    - /pricing-complete (pour voir les offres)
    - Toute la section ANALYSE DE MARCHÉ (8 pages)
    
    Args:
        username: Le nom d'utilisateur qui vient d'être créé
        
    Returns:
        True si succès, False si erreur
    """
    try:
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        # Ajouter chaque permission par dfaut
        for route in DEFAULT_USER_PERMISSIONS:
            if db_manager.use_postgresql:
                # Vrifier si existe dj
                c.execute(
                    "SELECT 1 FROM user_permissions WHERE username = %s AND route = %s",
                    (username, route)
                )
                if not c.fetchone():
                    c.execute(
                        "INSERT INTO user_permissions (username, route) VALUES (%s, %s)",
                        (username, route)
                    )
            else:
                # SQLite
                c.execute(
                    "SELECT 1 FROM user_permissions WHERE username = ? AND route = ?",
                    (username, route)
                )
                if not c.fetchone():
                    c.execute(
                        "INSERT INTO user_permissions (username, route) VALUES (?, ?)",
                        (username, route)
                    )
        
        conn.commit()
        conn.close()
        
        print(f"✅ Permissions par défaut attribuées à {username}: {len(DEFAULT_USER_PERMISSIONS)} pages")
        return True
        
    except Exception as e:
        print(f"❌ Erreur attribution permissions par défaut pour {username}: {e}")
        return False


# ===== Helpers: plan requis pour une route (UX page bloquée) =====
PLAN_LABELS = {"free": "Gratuit", "premium": "Premium", "advanced": "Advanced", "pro": "Pro", "elite": "Elite"}

def get_min_plan_for_route(route_key: str) -> str:
    """Retourne le plan minimal (le plus bas) qui donne accès à route_key, selon la config admin."""
    plan_order = ["free", "premium", "advanced", "pro", "elite"]
    rk = (route_key or "").strip().lstrip("/")
    if rk == "":
        rk = "dashboard"
    for plan in plan_order:
        try:
            if rk in get_plan_access_routes(plan):
                return plan
        except Exception:
            continue
    return "elite"

def normalize_route_key(route: str) -> str:
    """Normalise une route en 'clé' utilisée par le système de permissions.
    - retire /, querystring, #fragment
    - mappe les alias fréquents vers la même clé
    """
    rk = (route or "").strip()
    rk = rk.split("?", 1)[0].split("#", 1)[0]
    rk = rk.lstrip("/")
    if rk in ("", "/"):
        rk = "dashboard"

    # Aliases (URL -> clé permissions)
    alias = {
        "index": "dashboard",
        "home": "dashboard",
        "pricing": "pricing-complete",
        "plans": "pricing-complete",
        "plan": "pricing-complete",
        "tarifs": "pricing-complete",
        "pricing-complete": "pricing-complete",
        "admin": "admin-dashboard",
    }
    # garde la route telle quelle si pas d'alias
    rk = alias.get(rk, rk)
    return rk

def normalize_route(route: str) -> str:
    """Normalise une route (avec slash initial) pour la comparer aux clés de permissions."""
    key = normalize_route_key(route)
    # normalize_route_key renvoie sans slash (ex: 'pricing-complete'); on remet le slash.
    return '/' + key if key else '/'


def check_route_permission(user: dict, path: str) -> bool:
    """Décide si une route est accessible.

    Important:
    - Si l'utilisateur n'est pas loggé, on le traite comme plan 'free' pour les pages
      autorisées au plan Gratuit via 'Gestion des Accès par Forfait'.
    - Les routes 'admin' restent réservées aux admins.
    """
    try:
        route_path = normalize_route(path)

        # Routes réellement publiques
        PUBLIC_PREFIXES = (
            "/static", "/health", "/favicon.ico",
            "/login", "/logout", "/register", "/pricing", "/pricing-complete",
            "/tv-webhook", "/api", "/webhook", "/contact", "/terms", "/privacy",
            "/academy",  # Academy pages are public
        )
        if route_path in ("/", ""):
            return True
        if route_path.startswith(PUBLIC_PREFIXES):
            return True

        # Protection des routes admin
        if route_path.startswith("/admin"):
            return bool(user and (user.get("is_admin") or (user.get("user_role") == "admin")))

        is_logged_in = bool(user and ((user.get("username") or "").strip() or (user.get("email") or "").strip()))
        required_plan = get_required_plan_for_route(route_path)
        required_plan_norm = (str(required_plan).strip().lower() if required_plan else "")

        # Si la route n'est pas connue dans la matrice, on exige d'être loggé (sauf cas publics déjà gérés)
        if not required_plan_norm:
            return is_logged_in

        if not is_logged_in:
            # Non loggé = plan free
            return required_plan_norm in ("free", "gratuit")

        # Loggé: la comparaison de plan est faite ensuite dans PermissionMiddleware.
        return True
    except Exception as e:
        print(f"⚠️ check_route_permission error: {e}")
        return False

def start_background_monitor():
    """Démarre le monitor en arrière-plan sans faire planter l'app."""
    global monitor_running
    if monitor_running:
        return

    fn = globals().get("background_monitor")
    if not callable(fn) or not asyncio.iscoroutinefunction(fn):
        print("⚠️ start_background_monitor: background_monitor absent/non-async (désactivé).")
        return

    try:
        asyncio.create_task(fn())
        monitor_running = True
        print("🟢 Background monitor démarré.")
    except RuntimeError as e:
        # Pas de loop active (ne devrait pas arriver dans startup_event, mais safe)
        print(f"⚠️ start_background_monitor: impossible de démarrer (loop inactive): {e}")
