#  CORRECTION 2: Rate limiting sur login (max 5 tentatives / 15 minutes)
@app.post("/login")
@limiter.limit("5/15minutes")
async def login(request: Request, response: Response):
    """Traiter la connexion avec gestion des permissions"""
    form_data = await request.form()
    identifier = (form_data.get("email") or form_data.get("username") or "").strip()
    username = identifier
    password = form_data.get("password")
    redirect_url = form_data.get("redirect", "/")  # Redirection après login
    
    if db_manager.verify_user(username, password):
        #  Rcuprer les infos compltes de l'utilisateur
        user_info = db_manager.get_user_info(username)
        
        # Crer la session avec les infos d'abonnement
        token = create_session(username, user_info)
        
        redirect = RedirectResponse(url=redirect_url, status_code=303)
        # Cookie valable sur www + root (évite de "perdre" la session entre cryptoia.ca et www.cryptoia.ca)
        host = (request.url.hostname or "").lower()
        cookie_domain = ".cryptoia.ca" if host.endswith("cryptoia.ca") else None
        cookie_kwargs = dict(
            key="session_token",
            value=token,
            max_age=86400 * 7,  # 7 jours
            httponly=True,
            samesite="lax",
            path="/",
            secure=(request.url.scheme == "https"),
        )
        if cookie_domain:
            cookie_kwargs["domain"] = cookie_domain
        redirect.set_cookie(**cookie_kwargs)
        return redirect
    else:
        # Garder le redirect dans l'URL en cas d'erreur
        error_url = f"/login?error=1&redirect={redirect_url}" if redirect_url != "/" else "/login?error=1"
        return RedirectResponse(url=error_url, status_code=303)


# ============================================================================
# Alias /admin-login -> /login (compatibilité)
# ============================================================================
@app.get("/admin-login", response_class=HTMLResponse)
async def admin_login_alias_get(request: Request, next: str = "/admin-dashboard"):
    # On redirige vers la page de login principale en conservant ?next=
    try:
        # Éviter les URLs externes (open redirect)
        if not next or not str(next).startswith("/"):
            next = "/admin-dashboard"
    except Exception:
        next = "/admin-dashboard"
    return RedirectResponse(url=f"/login?next={next}", status_code=302)

@app.post("/admin-login")
async def admin_login_alias_post(request: Request):
    # Même comportement que /login (form POST) : on délègue en interne.
    form = await request.form()
    # Recréer la query next si fournie
    next_url = (form.get("next") or request.query_params.get("next") or "/admin-dashboard")
    if not str(next_url).startswith("/"):
        next_url = "/admin-dashboard"
    # On appelle la logique de login existante via une redirection POST->GET
    return RedirectResponse(url=f"/login?next={next_url}", status_code=303)


@app.get("/logout")
async def logout(request: Request):
    """Déconnexion (nettoie token + session Starlette)."""
    try:
        if isinstance(request.session, dict):
            request.session.clear()
    except Exception:
        pass

    resp = RedirectResponse(url="/login", status_code=303)

    # Cookies historiques + cookie de session Starlette
    for ck in ("session_token", "token", "access_token", "session"):
        resp.delete_cookie(ck)

    return resp

