async def get_permissions(username: str):
    """Récupérer les permissions d'un utilisateur"""
    try:
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        if db_manager.use_postgresql:
            c.execute("SELECT route FROM user_permissions WHERE LOWER(username) = LOWER(%s)", (username,))
        else:
            c.execute("SELECT route FROM user_permissions WHERE username = ?", (username,))
        
        routes = [row[0] for row in c.fetchall()]
        conn.close()
        
        return {"success": True, "routes": routes}
    except Exception as e:
        return {"success": False, "message": str(e)}


@app.post("/admin/change-password")
@app.post("/admin-dashboard/change-password")
async def change_password(request: Request):
    """Changer son propre mot de passe"""
    user_data = get_user_from_request(request)
    if not user_data:
        raise HTTPException(status_code=401, detail="Connexion requise")

    data = await request.json()
    new_password = data.get("newPassword") or data.get("password")
    if not new_password or len(str(new_password)) < 6:
        raise HTTPException(status_code=400, detail="Mot de passe trop court (min 6)")

    username = user_data.get("username")
    db_manager.change_password(username, new_password)
    return {"success": True, "message": "Mot de passe changé"}
