@app.post("/admin-dashboard/ebooks/delete", response_class=HTMLResponse)
async def admin_ebooks_delete(request: Request, id: int = Form(...)):
    user, resp = _require_admin(request)
    if resp:
        return resp
    try:
        conn = get_db_connection()
        c = conn.cursor()
        # Supprime la ligne
        c.execute("SELECT filename FROM ebooks WHERE id=?", (id,))
        row = c.fetchone()
        filename = row[0] if row else None
        c.execute("DELETE FROM ebooks WHERE id=?", (id,))
        conn.commit()
        conn.close()

        # Optionnel: supprimer fichier disque
        if filename:
            try:
                d = _ebooks_storage_dir()
                p = os.path.join(d, os.path.basename(filename))
                if os.path.exists(p):
                    os.remove(p)
            except Exception:
                pass
    except Exception:
        pass
    return RedirectResponse(url="/admin-dashboard/ebooks", status_code=303)


@app.post("/admin/pricing/update")
@app.post("/admin-dashboard/pricing/update")
async def admin_pricing_update(request: Request):
    """Update plan"""
    session_token = request.cookies.get("session_token")
    if not session_token:
        return RedirectResponse("/login", status_code=303)
    
    user = get_user_from_token(session_token)
    if not user or user.get("role") != "admin":
        return HTMLResponse(SIDEBAR + "<h1>403</h1>", status_code=403)
    
    try:
        form = await request.form()
        plan_id = form.get("plan_id")
        name = form.get("name")
        price = float(form.get("price", 0))
        duration = form.get("duration")
        routes = form.getlist("routes")
        
        import json, os
        config_file = "/data/pricing_config.json"
        
        if os.path.exists(config_file):
            with open(config_file, 'r') as f:
                config = json.load(f)
        else:
            config = {}
        
        config[plan_id] = {
            'name': name,
            'price': price,
            'duration': duration,
            'routes': routes,
            'updated_at': str(datetime.now())
        }
        
        os.makedirs("/data", exist_ok=True)
        with open(config_file, 'w') as f:
            json.dump(config, f, indent=2)
        
        return RedirectResponse("/admin/pricing?success=1", status_code=303)
    except Exception as e:
        print(f"Erreur: {e}")
        return RedirectResponse("/admin/pricing?error=1", status_code=303)


