@app.get("/admin/get-plan-access/{plan}")
async def admin_get_plan_access(plan: str, _admin: str = Depends(require_admin)):
    """Retourne les routes autorisées pour un plan."""
    plan_key = None
    try:
        # Normalisation robuste (supporte anciens alias)
        try:
            plan_key = normalize_plan_key(plan)
        except Exception:
            plan_key = normalize_plan(plan)
        routes = get_plan_access_routes(plan_key) or []
        # Normaliser les clés (peut arriver avec un "/" au début)
        routes = [str(r).lstrip("/").strip() for r in routes if str(r).strip()]
        return JSONResponse(
            {
                "success": True,
                "plan": plan_key,
                "routes": routes,
                "allowed": routes,
                "allowed_pages": routes,
                "possible_routes": PLAN_ROUTE_OPTIONS,
            }
        )
    except Exception as e:
        # Même en erreur, renvoyer un payload exploitable (évite UI vide)
        try:
            if not plan_key:
                plan_key = normalize_plan(plan)
        except Exception:
            plan_key = "free"
        try:
            routes = get_plan_access_routes(plan_key) or []
            routes = [str(r).lstrip("/").strip() for r in routes if str(r).strip()]
        except Exception:
            routes = []
        return JSONResponse(
            {
                "success": False,
                "plan": plan_key,
                "error": str(e),
                "routes": routes,
                "allowed": routes,
                "allowed_pages": routes,
                "possible_routes": PLAN_ROUTE_OPTIONS,
            },
            status_code=200,
        )

@app.post("/admin/save-plan-access")
async def admin_save_plan_access(request: Request, _admin: str = Depends(require_admin)):
    """Sauvegarde les permissions (routes) d'un plan depuis l'admin-dashboard."""
    try:
        payload = {}
        ct = (request.headers.get("content-type") or "").lower()

        if "application/json" in ct:
            try:
                payload = await request.json()
            except Exception:
                payload = {}
        elif "application/x-www-form-urlencoded" in ct or "multipart/form-data" in ct:
            try:
                form = await request.form()
                payload = dict(form)
            except Exception:
                payload = {}
        else:
            raw = await request.body()
            if raw:
                try:
                    payload = json.loads(raw.decode("utf-8"))
                except Exception:
                    payload = {}

        plan = payload.get("plan") or payload.get("selected_plan") or payload.get("plan_key") or "free"
        routes = (payload.get("routes") or payload.get("allowed") or payload.get("allowed_routes") or payload.get("allowedRoutes") or payload.get("access") or [])

        # Normaliser routes (peut arriver en string)
        if isinstance(routes, str):
            raw = routes.strip()
            if raw.startswith("[") and raw.endswith("]"):
                try:
                    routes = json.loads(raw)
                except Exception:
                    routes = [x.strip().strip('"').strip("'") for x in raw.strip("[]").split(",") if x.strip()]
            else:
                routes = [x.strip() for x in raw.split(",") if x.strip()]
        elif isinstance(routes, dict):
            routes = [k for k, v in routes.items() if str(v).lower() in ("1", "true", "yes", "on")]
        elif not isinstance(routes, list):
            routes = []

        plan_norm = normalize_plan(plan)
        ok, err = save_plan_access_routes(plan_norm, routes)
        if ok:
            saved = get_plan_access_routes(plan_norm)
            return JSONResponse({"success": True, "plan": plan_norm, "routes": saved})
        return JSONResponse({"success": False, "plan": plan_norm, "error": err or "Échec sauvegarde"})
    except Exception as e:
        return JSONResponse({"success": False, "error": str(e)})
@app.get("/admin/api/plan-prices")
async def admin_get_plan_prices(user=Depends(require_admin)):
    """Retourne les prix courants (CAD) pour remplir le formulaire Admin."""
    try:
        pricing = get_all_plan_pricing()  # dict {plan_key: {price_cents, ...}}
        out = {}
        for key in ("premium", "advanced", "pro", "elite"):
            pc = pricing.get(key, {}).get("price_cents")
            if pc is None:
                pc = DEFAULT_PLAN_PRICES[key]["price_cents"]
            out[key] = round(int(pc) / 100.0, 2)
        return JSONResponse(out, status_code=200)
    except Exception as e:
        print(f"❌ admin_get_plan_prices: {e}")
        out = {k: round(int(DEFAULT_PLAN_PRICES[k]['price_cents'])/100.0, 2) for k in ("premium","advanced","pro","elite")}
        return JSONResponse(out, status_code=200)

@app.post("/admin/save-plan-prices")
async def admin_save_plan_prices(request: Request, _admin: str = Depends(require_admin)):
    """Enregistre les prix (depuis l'UI admin)."""
    try:
        payload = {}
        ct = (request.headers.get("content-type") or "").lower()
        if "application/json" in ct:
            try:
                payload = await request.json()
            except Exception:
                payload = {}
        else:
            try:
                form = await request.form()
                payload = dict(form)
            except Exception:
                payload = {}

        plans = payload.get("plans") if isinstance(payload, dict) else None
        if not isinstance(plans, dict):
            # fallback: allow direct payload as plans dict
            plans = payload if isinstance(payload, dict) else {}

        key_map = {
            "premium": ("premium_1m", 30, "Premium"),
            "advanced": ("advanced_3m", 90, "Advanced"),
            "pro": ("pro_6m", 180, "Pro"),
            "elite": ("elite_12m", 365, "Elite"),
        }

        def parse_price_to_cents(v) -> int:
            if v is None:
                return None
            if isinstance(v, dict):
                # allow {"price_cents": 2999} or {"price": 29.99}
                if v.get("price_cents") is not None:
                    return int(v.get("price_cents"))
                v = v.get("price")
            if isinstance(v, (int, float)):
                return int(round(float(v) * 100))
            s = str(v).strip().replace(" ", "").replace(",", ".")
            if not s:
                return None
            return int(round(float(s) * 100))

        updated = []
        for ui_key, info in plans.items():
            ui_key_norm = str(ui_key).strip().lower()
            if ui_key_norm not in key_map:
                continue

            plan_key, default_days, default_name = key_map[ui_key_norm]

            # info can be a dict or a raw number/string
            if isinstance(info, dict):
                cents = parse_price_to_cents(info.get("price"))
                if cents is None:
                    cents = parse_price_to_cents(info.get("price_cents"))
                duration_days = int(info.get("duration_days") or default_days)
                currency = str(info.get("currency") or "cad").lower()
                display_name = str(info.get("display_name") or default_name)
            else:
                cents = parse_price_to_cents(info)
                duration_days = default_days
                currency = "cad"
                display_name = default_name

            if cents is None or cents <= 0:
                continue

            set_plan_pricing(
                plan_key=plan_key,
                display_name=display_name,
                duration_days=duration_days,
                price_cents=cents,
                currency=currency,
            )
            updated.append(plan_key)

        return JSONResponse({"success": True, "updated": updated})
    except Exception as e:
        return JSONResponse({"success": False, "error": str(e)}, status_code=200)



@app.post("/admin/save-prices")
async def admin_save_prices(prices: dict = Body(...), _admin: str = Depends(require_admin)):
    """Endpoint utilisé par l'UI /admin-dashboard (format simple).

    Attend: {premium: 19.99, advanced: 50.0, pro: 80.0, elite: 150.0}
    Enregistre dans settings.db (plan_pricing) pour que /pricing-complete reflète instantanément.
    """
    def _to_cents(v):
        if v is None:
            return None
        if isinstance(v, (int, float)):
            return int(round(float(v) * 100))
        s = str(v).strip().replace(' ', '').replace(',', '.')
        if not s:
            return None
        return int(round(float(s) * 100))

    key_map = {
        'premium': ('premium', 30, 'Premium'),
        'advanced': ('advanced', 90, 'Advanced'),
        'pro': ('pro', 180, 'Pro'),
        'elite': ('elite', 365, 'Elite'),
    }

    updated = []
    for ui_key, (plan_key, days, name) in key_map.items():
        cents = _to_cents(prices.get(ui_key))
        if cents is None:
            continue
        # Autoriser 0 uniquement pour free; ici on ignore <=0
        if cents <= 0:
            continue
        set_plan_pricing(plan_key=plan_key, display_name=name, duration_days=days, price_cents=cents, currency='cad')
        updated.append(plan_key)

    return JSONResponse({'success': True, 'updated': updated})

