@app.get("/api/validate-promo")
async def api_validate_promo(
    code: str,
    plan: str = "1_month",
    amount: float = 29.99,
    session_token: Optional[str] = Cookie(None)
):
    """Valide un code promo (version simplifiée pour nouveau système)"""
    user = get_user_from_token(session_token)
    if not user:
        return JSONResponse({"valid": False, "message": "Non authentifié"}, status_code=401)
    
    try:
        conn = db_manager.get_connection()
        cursor = conn.cursor()
        
        # Crer la table si elle n'existe pas
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS promo_codes (
                code TEXT PRIMARY KEY,
                discount REAL,
                type TEXT,
                valid_until TEXT,
                max_uses INTEGER,
                uses INTEGER DEFAULT 0,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP
            )
        """)
        conn.commit()
        
        # Chercher le code promo
        cursor.execute("""
            SELECT discount, type, valid_until, max_uses, uses
            FROM promo_codes
            WHERE UPPER(code) = UPPER(?)
        """, (code,))
        
        result = cursor.fetchone()
        
        if not result:
            cursor.close()
            conn.close()
            return JSONResponse({
                "valid": False,
                "message": "Code promo invalide",
                "original_amount": amount,
                "discount": 0,
                "final_amount": amount
            })
        
        discount_value, discount_type, valid_until, max_uses, current_uses = result
        
        # Vrifier la date d'expiration
        if valid_until:
            from datetime import datetime
            try:
                expiry_date = datetime.fromisoformat(valid_until.replace('Z', '+00:00'))
                if datetime.now() > expiry_date:
                    cursor.close()
                    conn.close()
                    return JSONResponse({
                        "valid": False,
                        "message": "Code promo expiré",
                        "original_amount": amount,
                        "discount": 0,
                        "final_amount": amount
                    })
            except:
                pass
        
        # Vrifier le nombre d'utilisations
        if max_uses and current_uses >= max_uses:
            cursor.close()
            conn.close()
            return JSONResponse({
                "valid": False,
                "message": "Code promo épuisé",
                "original_amount": amount,
                "discount": 0,
                "final_amount": amount
            })
        
        # Calculer le rabais
        if discount_type == 'percentage':
            discount_amount = amount * (discount_value / 100)
        else:  # fixed
            discount_amount = discount_value
        
        final_amount = max(0, amount - discount_amount)
        
        cursor.close()
        conn.close()
        
        return JSONResponse({
            "valid": True,
            "message": f"Code {code.upper()} appliqué!",
            "original_amount": amount,
            "discount": discount_amount,
            "final_amount": final_amount,
            "code": code.upper(),
            "savings": f"${discount_amount:.2f}"
        })
    
    except Exception as e:
        print(f"❌ Erreur validate_promo: {e}")
        import traceback
        traceback.print_exc()
        return JSONResponse({
            "valid": False,
            "message": f"Erreur: {str(e)}",
            "original_amount": amount,
            "discount": 0,
            "final_amount": amount
        }, status_code=500)


