def get_user_from_request(request):
    """Retourne l'utilisateur courant à partir d'un token de session.

    IMPORTANT: on **ne fait pas confiance** à request.session['user'] tout seul.
    - Le cookie de session (Starlette) peut survivre aux redéploiements.
    - Notre SessionManager est en mémoire (active_sessions) : le token est la source de vérité.
    """
    # Accepte plusieurs noms historiques de cookie, mais la référence est `session_token`
    token = (
        request.cookies.get("session_token")
        or request.cookies.get("token")
        or request.cookies.get("access_token")
    )

    if token:
        user = get_user_from_token(token)
        if user:
            # Synchronise (utile pour les templates), sans que ce soit la source d'auth
            try:
                if isinstance(request.session, dict):
                    request.session["user"] = {
                        "username": user.get("username", ""),
                        "email": user.get("email", ""),
                        "role": user.get("role", "user"),
                        "plan": user.get("plan", ""),
                    }
            except Exception:
                pass
            return user

    # Pas de token valide => considéré déconnecté (sécurité)
    return None

# Backward-compat: certaines pages appellent encore cette fonction
def get_current_user_from_session(request: Request) -> dict | None:
    """Retourne l'utilisateur courant depuis la session (alias)."""
    return get_user_from_request(request)

def is_admin_user(user: dict | None) -> bool:
    """Détermine si l’utilisateur doit bypass les restrictions (admin)."""
    if not user:
        return False
    if user.get("is_admin") is True:
        return True
    role = str(user.get("role") or "").strip().lower()
    if role in ("admin", "superadmin", "owner", "root"):
        return True
    username = str(user.get("username") or "").strip().lower()
    if username == "admin":
        return True
    return False


def _safe_get_user_plan(username, default: str = "free") -> str:
    try:
        if 'get_user_plan' in globals():
            func = globals().get('get_user_plan')
            if callable(func):
                try:
                    p = func(username)
                except TypeError:
                    # certaines implémentations attendent une string non-nulle
                    p = func(str(username) if username is not None else "")
                if p:
                    return str(p).strip().lower()
        return default
    except Exception:
        return default


class PermissionMiddleware(BaseHTTPMiddleware):
    """
    Middleware qui vérifie automatiquement les permissions pour TOUTES les routes.
    
    Routes PUBLIQUES (accessibles sans authentification):
    - /, /login, /register, /logout, /health, /api/*, /static/*
    
    Routes avec PERMISSIONS PAR DÉFAUT (accès minimum):
    - /pricing-complete
    - Section ANALYSE DE MARCHÉ (8 pages)
    
    Toutes les AUTRES routes = Vérification permission obligatoire
    """
    
    async def dispatch(self, request: Request, call_next):
        """Middleware d'accès (plans + admin).

        Objectifs:
        - Toujours peupler request.state.user
        - Admin: accès total à /admin/*
        - Non connecté: rediriger proprement vers /admin-login pour /admin/*
        - Plans: appliquer check_route_permission() pour le reste
        """

        path = request.url.path or "/"

        # Uniformiser: /pricing -> /pricing-complete (même design + mêmes forfaits)
        if path == "/pricing":
            qp = str(request.url.query).strip()
            target = "/pricing-complete" + (("?" + qp) if qp else "")
            return RedirectResponse(url=target, status_code=303)


        # --------- chemins publics / statiques ---------
        PUBLIC_PATHS = {
            "/", "/health", "/favicon.ico",
            "/login", "/logout", "/register",
            "/admin-login",
            "/contact", "/pricing", "/pricing-complete",
            "/telechargements", "/crypto-pepites",
            "/academy",
            "/crypto-academy",
            "/trading-academy",
            "/tv-webhook",
        }
        PUBLIC_PREFIXES = ("/static", "/assets", "/css", "/js", "/img")

        if path in PUBLIC_PATHS or path.startswith(PUBLIC_PREFIXES):
            return await call_next(request)

        # --------- utilisateur courant ---------
        user = None
        try:
            user = get_user_from_request(request)
        except Exception:
            user = None

        if not user:
            user = {"username": "", "role": "guest", "plan": "free"}

        # Enrichir rôle depuis la DB si manquant
        try:
            if user.get("username") and not user.get("role") and "db_manager" in globals():
                info = db_manager.get_user_info(user["username"])
                if isinstance(info, dict) and info.get("role"):
                    user["role"] = info["role"]
        except Exception:
            pass

        request.state.user = user

        username = (user.get("username") or "").strip()
        is_logged_in = bool(username)

        # Admin / bypass admin
        try:
            is_admin = is_admin_user(user)
        except Exception:
            is_admin = False

        # --------- /admin/* ---------
        if path.startswith("/admin") or path.startswith("/admin-dashboard"):
            # mode bypass (DEV seulement)
            if _admin_bypass_enabled():
                return await call_next(request)

            if not is_logged_in:
                next_url = request.url.path
                if request.url.query:
                    next_url += "?" + request.url.query
                return RedirectResponse(url=f"/admin-login?next={next_url}", status_code=302)

            # connecté mais pas admin -> interdit
            if not is_admin:
                return JSONResponse(
                    {"detail": "Accès refusé: section administrateur."},
                    status_code=403
                )

            # admin -> accès total
            return await call_next(request)

        # --------- reste du site: contrôle par plan ---------
        if is_admin:
            return await call_next(request)

        allowed = False
        try:
            allowed = check_route_permission(user, path)
        except Exception:
            allowed = False

        if allowed:
            return await call_next(request)

        # Refus : message propre + suggestion upgrade
        # (On renvoie JSON si appel AJAX, sinon on redirige vers /pricing)
        try:
            accept = request.headers.get("accept", "")
            is_ajax = request.headers.get("x-requested-with") == "XMLHttpRequest"
        except Exception:
            accept = ""
            is_ajax = False

        if is_ajax or "application/json" in accept:
            return JSONResponse(
                {"detail": "Accès refusé. Votre forfait ne permet pas cette page.", "upgrade": "/pricing-complete"},
                status_code=403
            )

        return RedirectResponse(url="/pricing-complete", status_code=302)
# Activer le middleware
app.add_middleware(PermissionMiddleware)


