async def _bybit_klines(symbol: str, interval: str, limit: int = 500, ttl_seconds: int = 60):
    """Fallback OHLCV spot depuis Bybit (API publique v5)."""
    interval_map = {"15m":"15","1h":"60","4h":"240","1d":"D"}
    iv = interval_map.get(interval, interval_map.get(str(interval), "60"))
    url = "https://api.bybit.com/v5/market/kline"
    params = {"category":"spot","symbol":symbol,"interval":iv,"limit":str(int(limit))}
    data = await _fetch_json(url, params=params, ttl_seconds=ttl_seconds)
    # Expected: {"retCode":0,"result":{"list":[[start,open,high,low,close,volume,turnover],...]}}
    if not isinstance(data, dict) or data.get("retCode") not in (0, "0"):
        raise RuntimeError(f"Bybit error: {data.get('retMsg') if isinstance(data, dict) else 'invalid'}")
    lst = (((data.get("result") or {}) .get("list")) or [])
    if not lst:
        raise RuntimeError("Bybit empty")
    # Bybit returns newest-first; convert to oldest-first and Binance-like schema
    out = []
    for row in reversed(lst):
        try:
            start_ms = int(row[0])
            o,h,l,c,v = row[1],row[2],row[3],row[4],row[5]
            out.append([start_ms, str(o), str(h), str(l), str(c), str(v), start_ms, "0", 0, "0", "0", "0"])
        except Exception:
            continue
    if len(out) < 5:
        raise RuntimeError("Bybit parse failed")
    return out

async def _coinbase_klines(symbol: str, interval: str, limit: int = 300, ttl_seconds: int = 60):
    """Fallback OHLCV depuis Coinbase Exchange (API publique)."""
    # Coinbase uses product ids like BTC-USD / ETH-BTC
    product_map = {"BTCUSDT":"BTC-USD","BTCUSD":"BTC-USD","ETHUSDT":"ETH-USD","ETHUSD":"ETH-USD","ETHBTC":"ETH-BTC"}
    product = product_map.get(symbol, None)
    if not product:
        # Try to infer "AAA BBB" style
        if symbol.endswith("USDT") or symbol.endswith("USD"):
            base = symbol[:-4]
            product = f"{base}-USD"
        elif symbol.endswith("BTC"):
            base = symbol[:-3]
            product = f"{base}-BTC"
        else:
            raise RuntimeError("Coinbase unsupported symbol")
    gran_map = {"15m":900,"1h":3600,"4h":14400,"1d":86400}
    gran = gran_map.get(interval, 3600)
    url = f"https://api.exchange.coinbase.com/products/{product}/candles"
    params = {"granularity": str(int(gran))}
    data = await _fetch_json(url, params=params, ttl_seconds=ttl_seconds)
    # data: [[time, low, high, open, close, volume], ...] newest-first
    if not isinstance(data, list) or not data:
        raise RuntimeError("Coinbase empty/invalid")
    out=[]
    for row in reversed(data[:int(limit)]):
        try:
            t = int(row[0]) * 1000
            low, high, opn, close, vol = row[1], row[2], row[3], row[4], row[5]
            out.append([t, str(opn), str(high), str(low), str(close), str(vol), t, "0", 0, "0", "0", "0"])
        except Exception:
            continue
    if len(out) < 5:
        raise RuntimeError("Coinbase parse failed")
    return out

async def _kraken_klines(symbol: str, interval: str, limit: int = 720, ttl_seconds: int = 60):
    """Fallback OHLCV depuis Kraken (API publique)."""
    # Kraken uses XBT instead of BTC for many pairs.
    pair_map = {"BTCUSDT":"XBTUSD","BTCUSD":"XBTUSD","ETHUSDT":"ETHUSD","ETHUSD":"ETHUSD","ETHBTC":"ETHXBT"}
    pair = pair_map.get(symbol, None)
    if not pair:
        if symbol.endswith("USDT") or symbol.endswith("USD"):
            base = symbol[:-4]
            pair = ("XBT" if base=="BTC" else base) + "USD"
        elif symbol.endswith("BTC"):
            base = symbol[:-3]
            pair = ("XBT" if base=="BTC" else base) + "XBT"
        else:
            raise RuntimeError("Kraken unsupported symbol")
    iv_map = {"15m":15,"1h":60,"4h":240,"1d":1440}
    iv = iv_map.get(interval, 60)
    url = "https://api.kraken.com/0/public/OHLC"
    params = {"pair": pair, "interval": str(int(iv))}
    data = await _fetch_json(url, params=params, ttl_seconds=ttl_seconds)
    if not isinstance(data, dict) or data.get("error"):
        raise RuntimeError(f"Kraken error: {data.get('error')}")
    result = data.get("result") or {}
    # result contains a key for the pair which may be different; find first list
    ohlc = None
    for k,v in result.items():
        if k == "last": 
            continue
        if isinstance(v, list) and v:
            ohlc = v
            break
    if not ohlc:
        raise RuntimeError("Kraken empty")
    # ohlc: [time, open, high, low, close, vwap, volume, count]
    out=[]
    # Keep last `limit` candles
    for row in ohlc[-int(limit):]:
        try:
            t = int(row[0]) * 1000
            opn, high, low, close, vol = row[1], row[2], row[3], row[4], row[6]
            out.append([t, str(opn), str(high), str(low), str(close), str(vol), t, "0", 0, "0", "0", "0"])
        except Exception:
            continue
    if len(out) < 5:
        raise RuntimeError("Kraken parse failed")
    return out

async def _get_spot_klines(symbol: str, interval: str, limit: int = 500):
    """Récupère des chandelles via plusieurs fournisseurs (évite les blocages HTTP 451)."""
    errors = []
    # 1) Binance (default)
    try:
        k = await _binance_klines(symbol, interval, limit=limit)
        if k and len(k) >= 5:
            return k, "binance"
    except Exception as e:
        errors.append(f"binance: {e}")
    # 2) Binance.US
    try:
        # Re-impl minimal inline to change host
        key = f"binanceus:{symbol}:{interval}:{limit}"
        cached = _cache_get(key)
        if cached is not None:
            return cached, "binance.us (cache)"
        url = "https://api.binance.us/api/v3/klines"
        params = {"symbol": symbol, "interval": interval, "limit": int(limit)}
        data = await _fetch_json(url, params=params, ttl_seconds=60)
        if not isinstance(data, list) or not data:
            raise RuntimeError("empty")
        _cache_set(key, data, ttl_seconds=60)
        return data, "binance.us"
    except Exception as e:
        errors.append(f"binance.us: {e}")
    # 3) Bybit
    try:
        k = await _bybit_klines(symbol, interval, limit=min(int(limit), 1000))
        if k and len(k) >= 5:
            return k, "bybit"
    except Exception as e:
        errors.append(f"bybit: {e}")
    # 4) Coinbase
    try:
        k = await _coinbase_klines(symbol, interval, limit=min(int(limit), 300))
        if k and len(k) >= 5:
            return k, "coinbase"
    except Exception as e:
        errors.append(f"coinbase: {e}")
    # 5) Kraken
    try:
        k = await _kraken_klines(symbol, interval, limit=min(int(limit), 720))
        if k and len(k) >= 5:
            return k, "kraken"
    except Exception as e:
        errors.append(f"kraken: {e}")
    raise RuntimeError("All providers failed: " + " | ".join(errors))


async def calculate_altcoin_season_index():
    """
    🔥 ALTCOIN SEASON INDEX - MÉTHODE BLOCKCHAIN CENTER (CORRECTE)
    
    Méthodologie officielle:
    1. Prendre les Top 50 cryptos (sans stablecoins/wrapped)
    2. Comparer CHAQUE crypto vs Bitcoin sur 90 jours
    3. Index = (nombre qui battent BTC / 50) × 100
    
    Si index = 37: 37% des top 50 ont battu BTC sur 90 jours
    Si index = 75+: C'est Altcoin Season!
    """
    try:
        async with httpx.AsyncClient(timeout=30.0) as client:
            print("🔄 Calcul Altcoin Season Index (méthode Blockchain Center)...")
            
            # 1. Rcuprer les Top 100 coins avec performance 90j en UNE SEULE requte!
            markets_response = await client.get(
                'https://api.coingecko.com/api/v3/coins/markets',
                params={
                    'vs_currency': 'cad',
                    'order': 'market_cap_desc',
                    'per_page': 100,
                    'page': 1,
                    'price_change_percentage': '90d'
                }
            )
            
            if markets_response.status_code != 200:
                raise Exception(f"CoinGecko API error: {markets_response.status_code}")
            
            coins_data = markets_response.json()
            
            # 2. Trouver Bitcoin et sa performance 90j
            btc_performance = None
            for coin in coins_data:
                if coin['symbol'].lower() == 'btc':
                    btc_performance = coin.get('price_change_percentage_90d_in_currency', 0)
                    print(f"📊 BTC 90d: +{btc_performance:.1f}%")
                    break
            
            if btc_performance is None:
                raise Exception("Bitcoin data not found")
            
            # 3. Filtrer: Top 50 altcoins (pas Bitcoin, pas stablecoins, pas wrapped)
            stablecoins = {'usdt', 'usdc', 'busd', 'dai', 'tusd', 'usdp', 'gusd', 'usdd'}
            wrapped = {'wbtc', 'steth', 'weth', 'renbtc', 'hbtc'}
            
            altcoins = []
            for coin in coins_data:
                symbol = coin['symbol'].lower()
                if symbol == 'btc':
                    continue
                if symbol in stablecoins or symbol in wrapped:
                    continue
                if coin.get('price_change_percentage_90d_in_currency') is not None:
                    altcoins.append(coin)
                if len(altcoins) >= 50:
                    break
            
            # 4. Compter combien battent Bitcoin
            alts_beating_btc = 0
            for alt in altcoins:
                alt_perf = alt.get('price_change_percentage_90d_in_currency', 0)
                if alt_perf > btc_performance:
                    alts_beating_btc += 1
            
            # 5. Calculer l'index
            total_compared = len(altcoins)
            if total_compared == 0:
                raise Exception("No altcoins data")
            
            index = (alts_beating_btc / total_compared) * 100
            
            print(f"📈 RÉSULTAT: {alts_beating_btc}/{total_compared} alts battent BTC")
            print(f"🎯 INDEX: {index:.1f}/100")
            
            # 6. Rcuprer dominances
            try:
                global_response = await client.get('https://api.coingecko.com/api/v3/global')
                global_data = global_response.json()['data']
                btc_dominance = global_data.get('market_cap_percentage', {}).get('btc', 0)
                eth_dominance = global_data.get('market_cap_percentage', {}).get('eth', 0)
            except:
                btc_dominance = 0
                eth_dominance = 0
            
            # 7. Dterminer phase base sur l'INDEX (pas la dominance!)
            if index >= 75:
                phase = "🔥 ALTCOIN SEASON"
                description = "Les altcoins EXPLOSENT!"
                momentum = "🚀 EXPLOSIF"
            elif index >= 60:
                phase = "📈 FORTE ROTATION ALTS"
                description = "Excellente performance altcoins"
                momentum = "🔥 TRÈS HOT"
            elif index >= 45:
                phase = "⚖️ PHASE MIXTE"
                description = "Marché équilibré BTC/Alts"
                momentum = "⚡ MODÉRÉ"
            elif index >= 25:
                phase = "📉 BTC DOMINE"
                description = "Bitcoin surperforme les alts"
                momentum = "😴 FAIBLE"
            else:
                phase = "❄️ BITCOIN SEASON"
                description = "Bitcoin écrase les altcoins"
                momentum = "🥶 GLACIAL"
            
            if index >= 75:
                trend = "🔥 Altcoin Season!"
            elif index >= 60:
                trend = "📈 Altcoins en hausse"
            elif index >= 40:
                trend = "⚖️ Phase mixte"
            elif index >= 25:
                trend = "📉 Bitcoin domine"
            else:
                trend = "❄️ Bitcoin Season"
            
            # Retourner les VRAIES donnes calcules
            return {
                "index": round(index, 1),
                "alts_winning": alts_beating_btc,  # Valeur réelle calculée!
                "total_compared": total_compared,  # Valeur réelle calculée!
                "phase": phase,
                "description": description,
                "trend": trend,
                "momentum": momentum,
                "btc_change_90d": round(btc_performance, 2),  # Performance réelle BTC 90j!
                "btc_dominance": round(btc_dominance, 2),
                "eth_dominance": round(eth_dominance, 2),
                "others_dominance": round(100 - btc_dominance - eth_dominance, 2),
                "status": "real_data",
                "source": "CoinGecko Top 50 vs BTC 90d (méthode Blockchain Center)",
                "timestamp": datetime.now().isoformat()
            }
            
    except Exception as e:
        print(f"❌ Erreur calcul altcoin: {e}")
        import traceback
        traceback.print_exc()
        raise

