@app.post("/admin-pricing")
async def admin_pricing_save(request: Request, user: dict = Depends(require_admin)):
    form = await request.form()

    # charger plans existants pour itérer
    current = get_all_plan_pricing()
    for plan_key in list(current.keys()):
        name = str(form.get(f"name__{plan_key}", current[plan_key].get("display_name", plan_key))).strip()
        currency = str(form.get(f"currency__{plan_key}", current[plan_key].get("currency", "CAD"))).strip().upper()[:4]
        try:
            price_cents = int(str(form.get(f"price__{plan_key}", current[plan_key].get("price_cents", 0))).strip() or "0")
        except Exception:
            price_cents = int(current[plan_key].get("price_cents", 0) or 0)
        try:
            duration_days = int(str(form.get(f"days__{plan_key}", current[plan_key].get("duration_days", 30))).strip() or "30")
        except Exception:
            duration_days = int(current[plan_key].get("duration_days", 30) or 30)

        # gardes
        if duration_days <= 0:
            duration_days = 30
        if price_cents < 0:
            price_cents = 0

        set_plan_pricing(plan_key=plan_key, display_name=name, price_cents=price_cents, duration_days=duration_days, currency=currency)

    return RedirectResponse(url="/admin-pricing?saved=1", status_code=303)



@app.post("/admin/reset-password")
async def admin_reset_password(request: Request, admin=Depends(require_admin)):
    """Reset / change password for a user.
    - If new_password is provided, set it.
    - Otherwise generate a random temporary password.
    Returns the password once so the admin can copy it.
    """
    # Accepte JSON, text/plain (JSON string) et form-urlencoded
    payload = {}
    try:
        payload = await request.json()
    except Exception:
        try:
            raw = (await request.body() or b"").decode("utf-8", errors="ignore").strip()
            if raw:
                import json as _json
                payload = _json.loads(raw)
        except Exception:
            try:
                form = await request.form()
                payload = dict(form)
            except Exception:
                payload = {}

    username = (payload.get("username") or payload.get("email") or "").strip()
    new_password = payload.get("new_password")
    if isinstance(new_password, str):
        new_password = new_password.strip()

    if not username:
        return JSONResponse({"success": False, "message": "Username manquant."}, status_code=400)

    if new_password:
        if len(new_password) < 8:
            return JSONResponse({"success": False, "message": "Mot de passe trop court (min 8 caractères)."}, status_code=400)
        password_to_set = new_password
    else:
        try:
            password_to_set = generate_temp_password()
        except NameError:
            # Fallback ultra-sûr si la fonction n'est pas dispo (évite 500)
            password_to_set = secrets.token_urlsafe(9)

    try:
        ok = db_manager.change_password(username, password_to_set)
    except Exception as e:
        print(f"❌ Reset password error for {username}: {e}")
        return JSONResponse({"success": False, "message": f"Erreur interne: {e}"}, status_code=500)

    if not ok:
        return JSONResponse({"success": False, "message": f"Utilisateur introuvable: {username}"}, status_code=404)

    return JSONResponse({
        "success": True,
        "message": "Mot de passe mis à jour.",
        "temp_password": password_to_set
    })


