@app.get("/admin/get-user/{username}")
@app.get("/admin-dashboard/get-user/{username}")
async def get_user_info(username: str):
    """Récupérer les informations d'un utilisateur"""
    try:
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        if db_manager.use_postgresql:
            c.execute("SELECT username, role, subscription_plan, created_at FROM users WHERE LOWER(username) = LOWER(%s)", (username,))
        else:
            c.execute("SELECT username, role, subscription_plan, created_at FROM users WHERE LOWER(username) = LOWER(?)", (username,))
        
        result = c.fetchone()
        conn.close()
        
        if result:
            return {
                "success": True,
                "user": {
                    "username": result[0],
                    "role": result[1],
                    "plan": result[2] if result[2] else "free",
                    "created_at": result[3]
                }
            }
        else:
            return {"success": False, "message": "Utilisateur non trouvé"}
    except Exception as e:
        return {"success": False, "message": str(e)}

@app.post("/admin/edit-user")
@app.post("/admin-dashboard/edit-user")
async def edit_user(request: Request):
    """Modifier un utilisateur existant"""
    try:
        data = await request.json()
        original_username = data.get("originalUsername")
        new_username = data.get("username")
        password = data.get("password")  # Optionnel
        role = data.get("role", "user")
        
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        # Mise  jour du rle (et username si diffrent)
        if db_manager.use_postgresql:
            if password:  # Si nouveau mot de passe fourni
                #  CORRECTION 1: Hash scuris avec bcrypt
                hashed_password = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                c.execute(
                    "UPDATE users SET username = %s, password_hash = %s, role = %s WHERE LOWER(username) = LOWER(%s)",
                    (new_username, hashed_password, role, original_username)
                )
            else:  # Pas de changement de mot de passe
                c.execute(
                    "UPDATE users SET username = %s, role = %s WHERE LOWER(username) = LOWER(%s)",
                    (new_username, role, original_username)
                )
        else:
            if password:
                #  CORRECTION 1: Hash scuris avec bcrypt
                hashed_password = bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')
                c.execute(
                    "UPDATE users SET username = ?, password_hash = ?, role = ? WHERE LOWER(username) = LOWER(?)",
                    (new_username, hashed_password, role, original_username)
                )
            else:
                c.execute(
                    "UPDATE users SET username = ?, role = ? WHERE LOWER(username) = LOWER(?)",
                    (new_username, role, original_username)
                )
        
        conn.commit()
        conn.close()
        
        return {"success": True, "message": f"Utilisateur modifié avec succès"}
    except Exception as e:
        return {"success": False, "message": f"Erreur: {str(e)}"}


@app.post("/admin/update-permissions")
@app.post("/admin-dashboard/update-permissions")
async def update_permissions(request: Request):
    """Mettre à jour les permissions d'un utilisateur"""
    try:
        data = await request.json()
        username = data.get("username")
        routes = data.get("routes", [])
        
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        # Supprimer les anciennes permissions
        if db_manager.use_postgresql:
            c.execute("DELETE FROM user_permissions WHERE LOWER(username) = LOWER(%s)", (username,))
        else:
            c.execute("DELETE FROM user_permissions WHERE LOWER(username) = LOWER(?)", (username,))
        
        # Ajouter les nouvelles permissions
        for route in routes:
            if db_manager.use_postgresql:
                c.execute("INSERT INTO user_permissions VALUES (%s, %s)", (username, route))
            else:
                c.execute("INSERT INTO user_permissions VALUES (?, ?)", (username, route))
        
        conn.commit()
        conn.close()
        
        return {"success": True, "message": f"Permissions mises à jour pour {username}"}
    except Exception as e:
        return {"success": False, "message": str(e)}

@app.get("/admin/get-permissions/{username}")
@app.get("/admin-dashboard/get-permissions/{username}")
async def get_permissions(username: str):
    """Récupérer les permissions d'un utilisateur"""
    try:
        conn = db_manager.get_connection()
        c = conn.cursor()
        
        if db_manager.use_postgresql:
            c.execute("SELECT route FROM user_permissions WHERE LOWER(username) = LOWER(%s)", (username,))
        else:
            c.execute("SELECT route FROM user_permissions WHERE username = ?", (username,))
        
        routes = [row[0] for row in c.fetchall()]
        conn.close()
        
        return {"success": True, "routes": routes}
    except Exception as e:
        return {"success": False, "message": str(e)}


@app.post("/admin/change-password")
@app.post("/admin-dashboard/change-password")
async def change_password(request: Request):
    """Changer son propre mot de passe"""
    user_data = get_user_from_request(request)
    if not user_data:
        raise HTTPException(status_code=401, detail="Connexion requise")

    data = await request.json()
    new_password = data.get("newPassword") or data.get("password")
    if not new_password or len(str(new_password)) < 6:
        raise HTTPException(status_code=400, detail="Mot de passe trop court (min 6)")

    username = user_data.get("username")
    db_manager.change_password(username, new_password)
    return {"success": True, "message": "Mot de passe changé"}
@app.post("/tv-webhook")
async def webhook(request: Request):
    """Endpoint webhook TradingView robuste (évite 422 + accepte différents formats).

    Supporte :
    - JSON normal (fields au root)
    - JSON encapsulé dans { "alert": { ... } }
    - text/plain contenant un JSON string
    - form-urlencoded / multipart
    """
    expected_secret = (os.getenv("TV_WEBHOOK_SECRET") or "").strip()
    provided_secret = (request.query_params.get("secret") or "").strip()
    if expected_secret and provided_secret != expected_secret:
        print("❌ Webhook secret invalide")
        return JSONResponse({"status": "error", "message": "Secret invalide"}, status_code=403)

    try:
        raw_body = await request.body()
    except Exception:
        raw_body = b""

    if not raw_body or raw_body.strip() == b"":
        return JSONResponse({"status": "ok", "message": "No payload (test ok)"}, status_code=200)

    payload: Any = None
    content_type = (request.headers.get("content-type") or "").lower()

    try:
        if "application/json" in content_type:
            payload = await request.json()
        elif "application/x-www-form-urlencoded" in content_type or "multipart/form-data" in content_type:
            form = await request.form()
            payload = dict(form)
            if isinstance(payload, dict) and len(payload) == 1:
                only_val = list(payload.values())[0]
                if isinstance(only_val, str) and only_val.strip().startswith("{"):
                    payload = json.loads(only_val)
        else:
            payload = json.loads(raw_body.decode("utf-8", errors="ignore"))
    except Exception:
        payload = {"raw": raw_body.decode("utf-8", errors="ignore")}

    def _to_float(v):
        try:
            if v is None:
                return None
            if isinstance(v, (int, float)):
                return float(v)
            s = str(v).replace(",", ".").strip()
            return float(s) if s else None
        except Exception:
            return None

    def _normalize(obj: Any) -> Dict[str, Any]:
        d: Dict[str, Any] = obj if isinstance(obj, dict) else {}
        if isinstance(d.get("alert"), dict):
            d = d["alert"]

        symbol = (d.get("symbol") or d.get("ticker") or d.get("pair") or d.get("SYMBOL") or "").strip()
        tf = (d.get("tf") or d.get("timeframe") or d.get("interval") or d.get("Timeframe") or d.get("TF") or "").strip()
        price = _to_float(d.get("entry") or d.get("price") or d.get("current_price") or d.get("close") or d.get("Entry"))
        signal = (d.get("side") or d.get("signal") or d.get("action") or d.get("Signal") or "").strip()

        side = signal
        s = (signal or "").lower()
        if "buy" in s or s in ("long", "bull", "entry_long", "enter_long", "achat"):
            side = "LONG"
        elif "sell" in s or s in ("short", "bear", "entry_short", "enter_short", "vente"):
            side = "SHORT"

        sl = _to_float(d.get("sl") or d.get("stop_loss") or d.get("stop") or d.get("stoploss") or d.get("Stop Loss"))
        tp1 = _to_float(d.get("tp1") or d.get("take_profit_1") or d.get("take_profit") or d.get("Take Profit 1"))
        tp2 = _to_float(d.get("tp2") or d.get("take_profit_2") or d.get("Take Profit 2"))
        tp3 = _to_float(d.get("tp3") or d.get("take_profit_3") or d.get("Take Profit 3"))

        return {
            "type": str(d.get("type") or "ENTRY").upper(),
            "symbol": symbol,
            "tf": tf or None,
            "tf_label": d.get("tf_label") or None,
            "side": side or None,
            "entry": price,
            "current_price": _to_float(d.get("current_price")) if d.get("current_price") is not None else price,
            "sl": sl,
            "tp1": tp1,
            "tp2": tp2,
            "tp3": tp3,
        }

    normalized = _normalize(payload)

    print(f"✅ Webhook reçu: {normalized.get('symbol') or '?'} {normalized.get('side') or '?'} {normalized.get('type') or '?'} tf={normalized.get('tf') or '?'}")

    try:
        trade = TradeWebhook(**normalized)
    except Exception as e:
        print(f"❌ TradeWebhook validation error: {e}")
        return JSONResponse({"status": "ok", "message": "Payload received but incomplete"}, status_code=200)

    try:
        await _handle_tradingview_webhook(trade)
    except Exception as e:
        print(f"❌ Erreur traitement webhook: {e}")

    return JSONResponse({"status": "ok"}, status_code=200)

