@app.post("/api/watchlist/add")
async def api_watchlist_add(request: Request):
    payload = await request.json()
    raw_symbol = (payload.get("symbol") or "").strip()
    target_price = payload.get("target_price")
    note = (payload.get("note") or "").strip()

    if not raw_symbol:
        return JSONResponse({"ok": False, "error": "Symbole requis (ex: BTC, ETH, SOL)"}, status_code=400)

    symbol = _wl_norm_symbol(raw_symbol)
    try:
        resolved = await _wl_resolve_cgid(symbol)
    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e)}, status_code=400)

    # Parse target_price (optional)
    tp = None
    if target_price not in (None, ""):
        try:
            tp = float(target_price)
        except Exception:
            return JSONResponse({"ok": False, "error": "target_price doit être un nombre (USD)"}, status_code=400)

    existing = _wl_find_item(symbol)
    if existing:
        existing["target_price"] = tp
        existing["note"] = note
        existing["cg_id"] = resolved["id"]
        existing["name"] = resolved.get("name") or existing.get("name") or symbol
        return JSONResponse({"ok": True, "updated": True, "item": existing})

    item = {
        "symbol": symbol,
        "name": resolved.get("name") or symbol,
        "cg_id": resolved["id"],
        "target_price": tp,
        "note": note,
        "added_at": datetime.utcnow().isoformat() + "Z",
    }
    watchlist_db.append(item)
    return JSONResponse({"ok": True, "updated": False, "item": item})

@app.delete("/api/watchlist/remove")
async def api_watchlist_remove(symbol: str):
    sym = _wl_norm_symbol(symbol)
    global watchlist_db
    watchlist_db = [it for it in watchlist_db if _wl_norm_symbol(it.get("symbol") or "") != sym]
    return JSONResponse({"ok": True})

@app.get("/api/watchlist/market")
async def api_watchlist_market(vs: str = "usd"):
    """
    Retourne la watchlist + les données live (prix, variations, etc.) depuis CoinGecko.
    ⚠️ Cache léger (≈25s) pour éviter rate-limit.
    """
    vs_currency = (vs or "usd").lower()
    try:
        market = await _wl_fetch_market(vs_currency=vs_currency, ttl_s=25)
    except Exception as e:
        return JSONResponse({"ok": False, "error": f"CoinGecko indisponible: {e}"}, status_code=503)

    by_id = {m.get("id"): m for m in (market or []) if m.get("id")}
    out = []
    for it in watchlist_db:
        cg_id = it.get("cg_id")
        m = by_id.get(cg_id, {})
        out.append({
            "symbol": it.get("symbol"),
            "name": it.get("name") or m.get("name") or it.get("symbol"),
            "cg_id": cg_id,
            "image": m.get("image"),
            "current_price": m.get("current_price"),
            "market_cap": m.get("market_cap"),
            "total_volume": m.get("total_volume"),
            "high_24h": m.get("high_24h"),
            "low_24h": m.get("low_24h"),
            "price_change_percentage_1h_in_currency": m.get("price_change_percentage_1h_in_currency"),
            "price_change_percentage_24h_in_currency": m.get("price_change_percentage_24h_in_currency"),
            "price_change_percentage_7d_in_currency": m.get("price_change_percentage_7d_in_currency"),
            "target_price": it.get("target_price"),
            "note": it.get("note"),
            "added_at": it.get("added_at"),
        })

    return JSONResponse({
        "ok": True,
        "vs": vs_currency,
        "updated_at": datetime.utcnow().isoformat() + "Z",
        "items": out
    })

@app.get("/api/watchlist/history")
async def api_watchlist_history(symbol: str, days: int = 7, vs: str = "usd"):
    """
    Historique de prix (pour le graphique) via CoinGecko /market_chart.
    days: 1..90 (CoinGecko)
    """
    sym = _wl_norm_symbol(symbol)
    it = _wl_find_item(sym)
    cg_id = (it or {}).get("cg_id")
    if not cg_id:
        try:
            resolved = await _wl_resolve_cgid(sym)
            cg_id = resolved["id"]
        except Exception as e:
            return JSONResponse({"ok": False, "error": str(e)}, status_code=400)

    d = max(1, min(int(days or 7), 90))
    vs_currency = (vs or "usd").lower()
    try:
        prices = await _wl_fetch_history(cg_id=cg_id, vs_currency=vs_currency, days=d, ttl_s=300)
    except Exception as e:
        return JSONResponse({"ok": False, "error": f"CoinGecko indisponible: {e}"}, status_code=503)

    return JSONResponse({
        "ok": True,
        "symbol": sym,
        "cg_id": cg_id,
        "vs": vs_currency,
        "days": d,
        "prices": prices,
    })

@app.get("/api/watchlist/check-alerts")
async def api_watchlist_check_alerts(vs: str = "usd"):
    """
    Vérifie les alertes de la watchlist en comparant current_price vs target_price.
    Retourne les alertes déclenchées (si target_price défini).
    """
    vs_currency = (vs or "usd").lower()
    market = await _wl_fetch_market(vs_currency=vs_currency, ttl_s=20)
    by_id = {m.get("id"): m for m in (market or []) if m.get("id")}

    triggered = []
    for it in watchlist_db:
        tp = it.get("target_price")
        if tp in (None, ""):
            continue
        cg_id = it.get("cg_id")
        m = by_id.get(cg_id, {})
        cur = m.get("current_price")
        if cur is None:
            continue
        try:
            if float(cur) >= float(tp):
                triggered.append({
                    "symbol": it.get("symbol"),
                    "name": it.get("name") or m.get("name") or it.get("symbol"),
                    "current_price": cur,
                    "target_price": tp,
                    "note": it.get("note") or "",
                })
        except Exception:
            continue

    return JSONResponse({"ok": True, "triggered": triggered})

@app.get("/api/ai/suggestions")
async def get_ai_suggestions():
    """Obtenir des suggestions IA basées sur les trades"""
    suggestions = []
    
    # Analyser les trades pour gnrer des suggestions
    if len(trades_db) >= 3:
        # Calculer le winrate global
        closed_trades = [t for t in trades_db if t.get("status") != "open"]
        if closed_trades:
            wins = len([t for t in closed_trades if t.get("pnl", 0) > 0])
            winrate = (wins / len(closed_trades)) * 100
            
            # Suggestion base sur le winrate
            if winrate < 50:
                suggestions.append({
                    "type": "warning",
                    "title": "⚠️ Winrate faible",
                    "message": f"Votre winrate est de {winrate:.1f}%. Envisagez de réviser votre stratégie.",
                    "priority": "high"
                })
            elif winrate > 70:
                suggestions.append({
                    "type": "success",
                    "title": "✅ Excellent winrate",
                    "message": f"Félicitations ! Votre winrate de {winrate:.1f}% est excellent.",
                    "priority": "info"
                })
            
            # Analyser les paires les plus profitables
            symbol_stats = {}
            for trade in closed_trades:
                symbol = trade.get("symbol", "")
                pnl = trade.get("pnl", 0)
                
                if symbol not in symbol_stats:
                    symbol_stats[symbol] = {"count": 0, "total_pnl": 0}
                
                symbol_stats[symbol]["count"] += 1
                symbol_stats[symbol]["total_pnl"] += pnl
            
            # Trouver la meilleure paire
            if symbol_stats:
                best_symbol = max(symbol_stats.items(), key=lambda x: x[1]["total_pnl"])
                if best_symbol[1]["count"] >= 2:
                    suggestions.append({
                        "type": "info",
                        "title": f"💎 Paire performante: {best_symbol[0]}",
                        "message": f"Vous avez {best_symbol[1]['count']} trades avec +{best_symbol[1]['total_pnl']:.2f}% de profit total.",
                        "priority": "medium"
                    })
            
            # Suggestion sur le risk management
            open_trades = [t for t in trades_db if t.get("status") == "open"]
            max_trades = risk_management_settings.get("max_open_trades", 3)
            
            if len(open_trades) >= max_trades:
                suggestions.append({
                    "type": "warning",
                    "title": "⚠️ Limite de trades atteinte",
                    "message": f"Vous avez {len(open_trades)} trades ouverts (limite: {max_trades}). Attendez avant d'ouvrir de nouvelles positions.",
                    "priority": "high"
                })
    else:
        suggestions.append({
            "type": "info",
            "title": "🎓 Commencez à trader",
            "message": "Ajoutez au moins 3 trades pour obtenir des suggestions personnalisées de l'IA.",
            "priority": "low"
        })
    
    # Mettre  jour les donnes IA
    ai_assistant_data["suggestions"] = suggestions
    ai_assistant_data["last_analysis"] = datetime.now().isoformat()
    
    return {"ok": True, "suggestions": suggestions, "last_analysis": ai_assistant_data["last_analysis"]}

@app.get("/api/ai/market-sentiment")
async def get_market_sentiment():
    """Analyser le sentiment du marché via Fear & Greed"""
    try:
        async with httpx.AsyncClient(timeout=5.0) as client:
            response = await client.get("https://api.alternative.me/fng/")
            if response.status_code == 200:
                data = response.json()
                value = int(data["data"][0]["value"])
                
                if value <= 25:
                    sentiment = "Extreme Fear - Opportunité d'achat"
                    color = "#ef4444"
                elif value <= 45:
                    sentiment = "Fear - Bon moment pour accumuler"
                    color = "#f59e0b"
                elif value <= 55:
                    sentiment = "Neutral - Marché équilibré"
                    color = "#94a3b8"
                elif value <= 75:
                    sentiment = "Greed - Soyez prudent"
                    color = "#10b981"
                else:
                    sentiment = "Extreme Greed - Prenez vos profits"
                    color = "#22c55e"
                
                return {
                    "ok": True,
                    "value": value,
                    "sentiment": sentiment,
                    "color": color
                }
    except:
        pass
    
    return {"ok": False, "error": "Impossible de récupérer le sentiment"}

