import asyncio

async def get_current_price_from_trade(trade: dict) -> float | None:
    """Retourne le prix actuel du symbole, de façon fiable.

    Problème observé: CoinGecko peut renvoyer un mauvais actif (même ticker), ou un spot qui ne correspond pas à MEXC Perp.
    -> On privilégie MEXC (ticker/price) avec un symbole normalisé, puis fallback sur le dernier prix connu du trade.
    """

    try:
        raw_symbol = str(trade.get("symbol") or "").strip()
        if not raw_symbol:
            return None

        # Normalisation TradingView (ex: 'MEXC:PLUMEUSDT.P' -> 'PLUMEUSDT')
        sym = raw_symbol.upper()
        if ":" in sym:
            sym = sym.split(":")[-1]
        sym = sym.replace(".P", "").replace("PERP", "").replace("PERPETUAL", "")
        sym = sym.replace("USDTP", "USDT")  # parfois suffixe perp
        sym = re.sub(r"[^A-Z0-9]", "", sym)

        # 1) Prix MEXC (vite les faux SL/TP)
        try:
            price = await get_mexc_price(sym)
            if price is not None:
                return float(price)
        except Exception:
            pass

        # 2) Dernier prix connu du webhook (si prsent)
        last = trade.get("current_price")
        if last is not None:
            try:
                return float(last)
            except Exception:
                pass

        return None
    except Exception:
        return None

async def check_tp_sl_automatic(trade: dict, current_price: float) -> dict:
    """
    Vérifie automatiquement si les TP ou SL sont atteints
    Retourne un dictionnaire avec les mises à jour à appliquer
    """
    updates = {}
    side = trade.get("side", "LONG")
    symbol = trade.get("symbol")
    
    # Vrifier TP1
    if trade.get("tp1") and not trade.get("tp1_hit"):
        if (side == "LONG" and current_price >= trade["tp1"]) or \
           (side == "SHORT" and current_price <= trade["tp1"]):
            updates["tp1_hit"] = True
            print(f"🎯 {symbol} - TP1 atteint ! Prix: ${current_price}")
            await send_telegram_target_notification(symbol, "TP1", current_price, trade["tp1"])
    
    # Vrifier TP2
    if trade.get("tp2") and not trade.get("tp2_hit"):
        if (side == "LONG" and current_price >= trade["tp2"]) or \
           (side == "SHORT" and current_price <= trade["tp2"]):
            updates["tp2_hit"] = True
            print(f"🎯🎯 {symbol} - TP2 atteint ! Prix: ${current_price}")
            await send_telegram_target_notification(symbol, "TP2", current_price, trade["tp2"])
    
    # Vrifier TP3
    if trade.get("tp3") and not trade.get("tp3_hit"):
        if (side == "LONG" and current_price >= trade["tp3"]) or \
           (side == "SHORT" and current_price <= trade["tp3"]):
            updates["tp3_hit"] = True
            print(f"🎯🎯🎯 {symbol} - TP3 atteint ! Prix: ${current_price}")
            await send_telegram_target_notification(symbol, "TP3", current_price, trade["tp3"])
    
    # Vrifier SL
    if trade.get("sl") and not trade.get("sl_hit"):
        if (side == "LONG" and current_price <= trade["sl"]) or \
           (side == "SHORT" and current_price >= trade["sl"]):
            updates["sl_hit"] = True
            updates["status"] = "closed"
            print(f"❌ {symbol} - SL touché ! Prix: ${current_price}")
            await send_telegram_target_notification(symbol, "SL", current_price, trade["sl"])
    
    return updates

async def send_telegram_target_notification(symbol: str, target: str, current_price: float, target_price: float):
    """Envoie une notification Telegram quand un TP ou SL est atteint"""
    try:
        emoji = "🎯" if "TP" in target else "❌"
        color = "✅" if "TP" in target else "🔴"
        
        message = f"""
{emoji} <b>{target} ATTEINT !</b> {color}

💰 <b>{symbol}</b>
📊 Prix actuel: <code>{format_price(current_price)}</code>
🎯 {target}: <code>{format_price(target_price)}</code>

⏰ {datetime.now(pytz.timezone('America/Montreal')).strftime('%H:%M:%S')}
"""
        
        # Ajouter message de flicitation pour TP3
        if target == "TP3":
            message += "\n🎉🎊 <b>FÉLICITATIONS ! TRADE COMPLÉTÉ !</b> 🎊🎉\n"
        
        #  NOUVEAU: Ajouter boutons dashboard + TradingView
        tradingview_url = f"https://www.tradingview.com/chart/?symbol=BINANCE:{symbol}"
        
        telegram_payload = {
            "chat_id": TELEGRAM_CHAT_ID, 
            "text": message, 
            "parse_mode": "HTML",
            "reply_markup": {
                "inline_keyboard": [
                    [
                        {
                            "text": "📊 Dashboard",
                            "url": "https://www.cryptoia.ca/"
                        },
                        {
                            "text": "📈 TradingView",
                            "url": tradingview_url
                        }
                    ]
                ]
            }
        }
        
        async with httpx.AsyncClient() as client:
            await client.post(
                f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/sendMessage",
                json=telegram_payload
            )
    except Exception as e:
        print(f"⚠️ Erreur Telegram: {e}")


async def monitor_trades_background():
    """Tâche de fond - surveillance automatique toutes les 30 secondes"""
    global monitor_running
    
    # Vrifier si une instance est dj en cours
    async with monitor_lock:
        if monitor_running:
            print("⚠️ Une instance du moniteur est déjà active, skip")
            return
        monitor_running = True
    
    print("\n" + "="*70)
    print("🤖 MONITEUR AUTOMATIQUE DES TP/SL DÉMARRÉ")
    print("   Vérification toutes les 30 secondes")
    print("   Utilise current_price du webhook Pine Script")
    print("="*70 + "\n")
    
    while True:
        try:
            await asyncio.sleep(30)  # Attendre 30 secondes
            
            # Rcuprer tous les trades ouverts
            open_trades = [t for t in trades_db if t.get("status") == "open"]
            
            if len(open_trades) == 0:
                # Ne rien afficher quand il n'y a pas de trades (rduire le spam)
                continue
            
            print(f"\n🔍 Vérification de {len(open_trades)} trade(s)...")
            
            for trade in open_trades:
                symbol = trade.get("symbol")
                if not symbol:
                    continue
                
                # Rcuprer le prix actuel (current_price du webhook stock dans le trade)
                current_price = await get_current_price_from_trade(trade)
                if current_price is None:
                    continue
                
                # Vrifier les TP/SL
                updates = await check_tp_sl_automatic(trade, current_price)
                
                # Appliquer les mises  jour
                if updates:
                    for key, value in updates.items():
                        trade[key] = value
                    print(f"✅ Trade {symbol} mis à jour")
            
            print("✅ Vérification terminée\n")
            
        except Exception as e:
            print(f"❌ Erreur monitoring: {e}")
            await asyncio.sleep(30)


@app.on_event("startup")
async def startup_event():
    """Démarre la tâche de fond au lancement de l'application"""
    # Initialiser la DB Portfolio
    init_portfolio_db()

    # ✅ Initialiser la DB des accès par forfait (settings.db)
    try:
        init_plan_access_db()
    except Exception as e:
        print(f"⚠️ init_plan_access_db (startup): {e}")
    
    #  CORRECTION: Initialiser la table ebooks
    init_ebooks_table()
    
    # Initialiser la DB Academy
    try:
        init_academy_db()
        print("✅ Academy DB créée dans startup_event")
    except Exception as e:
        print(f"⚠️ Erreur Academy DB startup: {e}")
    
    # Initialiser l'Academy
    # Utiliser try_lock pour viter de bloquer si un autre worker a dj lanc
    if not monitor_running:
        asyncio.create_task(monitor_trades_background())
    
    #  Dmarrer le monitoring MEXC pour auto-dtection TP/SL
    start_background_monitor()


