@app.post("/api/stripe-checkout")
async def stripe_checkout(request: Request):
    """Crée une session Stripe Checkout avec support des codes promo"""
    try:
        data = await request.json()
        plan = data.get('plan', 'premium')
        plan_key = normalize_plan(plan)
        plan_info = get_plan_pricing(plan_key) or {}
        amount = round(float(plan_info.get('price_cents', 2000)) / 100.0, 2)  # server price
        promo_code = data.get('promo_code', None)
        email = data.get('email', 'user@example.com')
        
        # Rcuprer l'email de l'utilisateur connect si disponible
        session_token = request.cookies.get("session_token")
        user = get_user_from_token(session_token)
        if user:
            email = user.get('username', email)
        
        if not STRIPE_AVAILABLE or not STRIPE_SECRET_KEY:
            return JSONResponse({
                "success": False,
                "message": "Stripe non configuré"
            }, status_code=500)
        
        if not PAYMENT_SYSTEM_AVAILABLE:
            return JSONResponse({
                "success": False,
                "message": "Payment system non disponible"
            }, status_code=500)
        
        # Valider et appliquer le code promo (NOUVEAU SYSTME)
        final_amount = amount
        discount_applied = 0
        
        if promo_code:
            try:
                conn = db_manager.get_connection()
                cursor = conn.cursor()
                
                # Chercher le code promo dans la nouvelle table
                cursor.execute("""
                    SELECT discount, type, valid_until, max_uses, uses
                    FROM promo_codes
                    WHERE UPPER(code) = UPPER(?)
                """, (promo_code,))
                
                result = cursor.fetchone()
                
                if result:
                    discount_value, discount_type, valid_until, max_uses, current_uses = result
                    
                    # Vrifier expiration
                    valid = True
                    if valid_until:
                        from datetime import datetime
                        try:
                            expiry_date = datetime.fromisoformat(valid_until.replace('Z', '+00:00'))
                            if datetime.now() > expiry_date:
                                valid = False
                                print(f"⚠️ Code {promo_code} expiré")
                        except:
                            pass
                    
                    # Vrifier utilisations
                    if valid and max_uses and current_uses >= max_uses:
                        valid = False
                        print(f"⚠️ Code {promo_code} épuisé ({current_uses}/{max_uses})")
                    
                    if valid:
                        # Calculer le rabais
                        if discount_type == 'percentage':
                            discount_applied = amount * (discount_value / 100)
                        else:  # fixed
                            discount_applied = discount_value
                        
                        final_amount = max(0, amount - discount_applied)
                        
                        # Incrmenter l'utilisation
                        cursor.execute("""
                            UPDATE promo_codes 
                            SET uses = uses + 1
                            WHERE UPPER(code) = UPPER(?)
                        """, (promo_code,))
                        conn.commit()
                        
                        print(f"✅ Code promo {promo_code} appliqué: -${discount_applied:.2f} (${amount:.2f} → ${final_amount:.2f})")
                    else:
                        print(f"⚠️ Code promo '{promo_code}' invalide")
                else:
                    print(f"⚠️ Code promo '{promo_code}' non trouvé")
                
                cursor.close()
                conn.close()
            except Exception as e:
                print(f"❌ Erreur validation promo: {e}")
                import traceback
                traceback.print_exc()
        
        # URLs
        base_url = "https://tradingview-production-5763.up.railway.app"
        success_url = f"{base_url}/api/payment-success?plan={plan}"
        cancel_url = f"{base_url}/api/payment-cancel?plan={plan}"
        
        # Crer session avec montant final (avec rduction)
        checkout_url, error = create_stripe_checkout_session(
            plan, email, success_url, cancel_url, final_amount
        )
        
        if error:
            return JSONResponse({
                "success": False,
                "message": error
            }, status_code=400)
        
        print(f"✅ Session Stripe créée: {plan} pour {email} (${final_amount:.2f})")
        return JSONResponse({
            "success": True,
            "url": checkout_url,
            "checkout_url": checkout_url
        })
    
    except Exception as e:
        print(f"❌ Stripe error: {e}")
        return JSONResponse({
            "success": False,
            "message": str(e)
        }, status_code=500)

@app.post("/api/coinbase-checkout")
async def coinbase_checkout(request: Request):
    """Crée un paiement Coinbase Commerce avec support des codes promo"""
    try:
        data = await request.json()
        plan = data.get('plan', 'premium')
        plan_key = normalize_plan(plan)
        plan_info = get_plan_pricing(plan_key) or {}
        amount = round(float(plan_info.get('price_cents', 2000)) / 100.0, 2)  # server price
        promo_code = data.get('promo_code', None)
        email = data.get('email', 'user@example.com')
        
        # Rcuprer l'email de l'utilisateur connect si disponible
        session_token = request.cookies.get("session_token")
        user = get_user_from_token(session_token)
        if user:
            email = user.get('username', email)
        
        print(f"🔵 Demande Coinbase: plan={plan}, amount=${amount}, email={email}, promo={promo_code}")
        if amount <= 0:
            return JSONResponse({"success": False, "message": "Plan invalide"}, status_code=400)

        
        if not COINBASE_AVAILABLE or not coinbase_client:
            error_msg = "Coinbase Commerce non configuré - Vérifiez COINBASE_COMMERCE_KEY"
            print(f"❌ {error_msg}")
            return JSONResponse({
                "success": False,
                "message": error_msg
            }, status_code=500)
        
        # Valider et appliquer le code promo (NOUVEAU SYSTME)
        final_amount = amount
        discount_applied = 0
        
        if promo_code:
            try:
                conn = db_manager.get_connection()
                cursor = conn.cursor()
                
                # Chercher le code promo dans la nouvelle table
                cursor.execute("""
                    SELECT discount, type, valid_until, max_uses, uses
                    FROM promo_codes
                    WHERE UPPER(code) = UPPER(?)
                """, (promo_code,))
                
                result = cursor.fetchone()
                
                if result:
                    discount_value, discount_type, valid_until, max_uses, current_uses = result
                    
                    # Vrifier expiration
                    valid = True
                    if valid_until:
                        from datetime import datetime
                        try:
                            expiry_date = datetime.fromisoformat(valid_until.replace('Z', '+00:00'))
                            if datetime.now() > expiry_date:
                                valid = False
                                print(f"⚠️ Code {promo_code} expiré")
                        except:
                            pass
                    
                    # Vrifier utilisations
                    if valid and max_uses and current_uses >= max_uses:
                        valid = False
                        print(f"⚠️ Code {promo_code} épuisé ({current_uses}/{max_uses})")
                    
                    if valid:
                        # Calculer le rabais
                        if discount_type == 'percentage':
                            discount_applied = amount * (discount_value / 100)
                        else:  # fixed
                            discount_applied = discount_value
                        
                        final_amount = max(0, amount - discount_applied)
                        
                        # Incrmenter l'utilisation
                        cursor.execute("""
                            UPDATE promo_codes 
                            SET uses = uses + 1
                            WHERE UPPER(code) = UPPER(?)
                        """, (promo_code,))
                        conn.commit()
                        
                        print(f"✅ Code promo {promo_code} appliqué: -${discount_applied:.2f} (${amount:.2f} → ${final_amount:.2f})")
                    else:
                        print(f"⚠️ Code promo '{promo_code}' invalide")
                else:
                    print(f"⚠️ Code promo '{promo_code}' non trouvé")
                
                cursor.close()
                conn.close()
            except Exception as e:
                print(f"❌ Erreur validation promo: {e}")
                import traceback
                traceback.print_exc()
        
        # Crer charge Coinbase avec montant final
        charge, error = create_coinbase_payment(plan, email, coinbase_client, final_amount)
        
        if error:
            print(f"❌ Erreur création charge: {error}")
            return JSONResponse({
                "success": False,
                "message": f"Erreur Coinbase: {error}"
            }, status_code=400)
        
        if not charge or not hasattr(charge, 'hosted_url'):
            print(f"❌ Charge invalide: {charge}")
            return JSONResponse({
                "success": False,
                "message": "Charge Coinbase invalide - pas d'URL générée"
            }, status_code=500)
        
        print(f"✅ Charge Coinbase créée: {charge.id} (${final_amount:.2f})")
        print(f"🔗 URL de paiement: {charge.hosted_url}")
        
        return JSONResponse({
            "success": True,
            "url": charge.hosted_url,
            "hosted_url": charge.hosted_url,
            "charge_id": charge.id,
            "plan": plan,
            "amount": final_amount
        })
    
    except Exception as e:
        print(f"❌ Exception Coinbase checkout: {type(e).__name__}: {str(e)}")
        import traceback
        traceback.print_exc()
        return JSONResponse({
            "success": False,
            "message": f"Erreur serveur: {str(e)}"
        }, status_code=500)

