def init_pricing_plans_table() -> None:
    # Ensure pricing_plans table exists in settings DB.
    try:
        conn = get_settings_db_connection()
        c = conn.cursor()
        c.execute("""
            CREATE TABLE IF NOT EXISTS pricing_plans (
                plan_name TEXT PRIMARY KEY,
                features TEXT DEFAULT '[]',
                updated_at TEXT
            )
        """)
        # Seed basic rows
        import json
        now = datetime.utcnow().isoformat()
        for plan_key in ["free", "premium", "advanced", "pro", "elite"]:
            c.execute(
                "INSERT OR IGNORE INTO pricing_plans (plan_name, features, updated_at) VALUES (?,?,?)",
                (plan_key, json.dumps([]), now)
            )
        conn.commit()
        conn.close()
    except Exception as e:
        # If using Postgres settings DB, or if get_settings_db_connection is not available
        try:
            cfg_type = (DB_CONFIG.get("type") or "sqlite").lower()
            if cfg_type != "postgres":
                raise
            conn = get_db_connection()
            c = conn.cursor()
            c.execute("""
                CREATE TABLE IF NOT EXISTS pricing_plans (
                    plan_name TEXT PRIMARY KEY,
                    features TEXT DEFAULT '[]',
                    updated_at TEXT
                )
            """)
            conn.commit()
            conn.close()
        except Exception as e2:
            print(f"⚠️ init_pricing_plans_table: {e} / {e2}")

