@app.get("/admin/update-plan-features", response_class=HTMLResponse)
@app.get("/admin-dashboard/update-plan-features", response_class=HTMLResponse)
async def admin_update_plan_features_page(request: Request):
    """Page admin pour modifier les features d'un plan"""
    # On vrifie si l'utilisateur est admin
    user = get_user_from_token(request.cookies.get("session_token"))
    if not user or user.get('role') != 'admin':
        raise HTTPException(status_code=403, detail="Accès refusé")
    
    # Rcuprer les plans existants pour les afficher dans un formulaire

    init_pricing_plans_table()
    try:
        conn = get_settings_db_connection()
        c = conn.cursor()
        c.execute("SELECT plan_name, features FROM pricing_plans")
        plans = c.fetchall()
        conn.close()
    except Exception:
        # Fallback to main DB if settings DB isn't available
        conn = get_db_connection()
        c = conn.cursor()
        try:
            c.execute("SELECT plan_name, features FROM pricing_plans")
            plans = c.fetchall()
        except Exception:
            plans = []
        conn.close()
    
    plans_html = ""
    for plan_name, features_json in plans:
        plans_html += f"<h3>Plan: {plan_name}</h3><textarea name='features_{plan_name}' rows='5' style='width:100%'>{features_json}</textarea><br><br>"

    return HTMLResponse(SIDEBAR + f"""
    <!DOCTYPE html>
    <html lang="fr">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Admin Plans | {SITE_NAME}</title>
        <script src="https://cdn.tailwindcss.com"></script>
        <link href="https://cdn.jsdelivr.net/npm/remixicon@4.0.0/fonts/remixicon.css" rel="stylesheet">
        <style>
            .gradient-bg {{ background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); }}
            .glass-effect {{ background: rgba(255, 255, 255, 0.1); backdrop-filter: blur(10px); border: 1px solid rgba(255, 255, 255, 0.2); }}
        </style>
    </head>
    <body class="bg-gray-900 text-white min-h-screen">
        
        <div class="container mx-auto px-4 py-8">
            <div class="max-w-4xl mx-auto">
                <h1 class="text-4xl font-bold text-center mb-8">⚙️ Modifier les fonctionnalités des plans</h1>
                <div class="glass-effect rounded-xl p-8">
                    <p class="mb-6 text-gray-300">Modifiez les fonctionnalités (au format JSON) pour chaque plan.</p>
                    <form action="/admin/update-plan-features" method="POST" class="space-y-6">
                        {plans_html}
                        <div class="flex justify-center">
                            <button type="submit" class="gradient-bg text-white px-8 py-3 rounded-lg font-semibold hover:opacity-90 transition">
                                <i class="ri-save-line mr-2"></i> Mettre à jour tous les plans
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </div>
    </body>
    </html>
    """)

@app.post("/admin/update-plan-features")
@app.post("/admin-dashboard/update-plan-features")
async def update_plan_features(request: Request):
    """Met à jour les features des plans.

    - Si appelé depuis le formulaire HTML: accepte form-data avec fields features_<plan> (JSON).
    - Si appelé en API: accepte JSON {plan: <plan>, features: <list>}.
    """
    user = get_user_from_token(request.cookies.get("session_token"))
    if not user or user.get('role') != 'admin':
        raise HTTPException(status_code=403, detail="Accès refusé")

    init_pricing_plans_table()
    import json

    content_type = (request.headers.get('content-type') or '').lower()
    updated = []

    # 1) JSON API: update single plan
    if 'application/json' in content_type:
        try:
            data = await request.json()
        except Exception:
            data = {}
        plan = normalize_plan(str(data.get('plan') or ''))
        features = data.get('features', [])
        if not plan:
            raise HTTPException(status_code=400, detail="Plan manquant")
        if not isinstance(features, (list, dict, str)):
            features = []
        if isinstance(features, (dict, list)):
            features_json = json.dumps(features)
        else:
            # string: try parse
            try:
                features_json = json.dumps(json.loads(str(features)))
            except Exception:
                features_json = json.dumps([])

        conn = get_settings_db_connection()
        c = conn.cursor()
        now = datetime.utcnow().isoformat()
        c.execute("UPDATE pricing_plans SET features = ?, updated_at = ? WHERE plan_name = ?", (features_json, now, plan))
        conn.commit()
        conn.close()
        return {'success': True, 'message': f'Plan {plan} mis à jour'}

    # 2) Form submission: update all plans present in form
    form = await request.form()
    conn = get_settings_db_connection()
    c = conn.cursor()
    now = datetime.utcnow().isoformat()

    for key, val in form.items():
        if not key.startswith('features_'):
            continue
        plan = normalize_plan(key.replace('features_', '').strip())
        raw = (val or '').strip()
        if not plan:
            continue
        try:
            parsed = json.loads(raw) if raw else []
        except Exception:
            # allow simple newline list
            parsed = [x.strip() for x in raw.splitlines() if x.strip()] if raw else []
        features_json = json.dumps(parsed)
        c.execute("UPDATE pricing_plans SET features = ?, updated_at = ? WHERE plan_name = ?", (features_json, now, plan))
        updated.append(plan)

    conn.commit()
    conn.close()

    # Return a friendly HTML redirect after form submit
    if updated:
        return RedirectResponse(url="/admin-dashboard/update-plan-features", status_code=303)
    return {'success': True, 'message': 'Aucune modification'}

