# ========== 1. AI SIGNALS - SIGNAUX DE TRADING ==========

# ---------------------------------------------------------------------
# AI SIGNALS (v2): données réelles (CoinGecko) + rendu pro + auto-refresh
# ---------------------------------------------------------------------
_AI_SIGNALS_CACHE = {"ts": 0.0, "payload": None}
_AI_SIGNALS_CACHE_TTL = 45  # secondes (évite de spammer l'API avec l'auto-refresh)

def _fmt_money(x: float) -> str:
    try:
        x = float(x or 0)
    except Exception:
        x = 0.0
    if x <= 0:
        return "—"
    if x >= 1_000_000_000:
        return f"${x/1_000_000_000:.2f}B"
    if x >= 1_000_000:
        return f"${x/1_000_000:.2f}M"
    if x >= 1_000:
        return f"${x/1_000:.2f}K"
    return f"${x:.2f}"

def _fmt_price(x: float) -> str:
    try:
        x = float(x or 0)
    except Exception:
        x = 0.0
    if x >= 1000:
        return f"${x:,.0f}"
    if x >= 1:
        return f"${x:,.2f}"
    if x >= 0.01:
        return f"${x:,.4f}"
    return f"${x:.8f}"

def _safe_float(v, default: float = 0.0) -> float:
    try:
        if v is None:
            return default
        return float(v)
    except Exception:
        return default

def _ai_signal_from_coin(coin: dict) -> dict:
    """Calcule un signal simple à partir des variations + liquidité (volume/marketcap)."""
    ch24 = _safe_float(coin.get("price_change_percentage_24h"), 0.0)
    ch7 = _safe_float(coin.get("price_change_percentage_7d_in_currency"), 0.0)
    vol = _safe_float(coin.get("total_volume"), 0.0)
    mc = _safe_float(coin.get("market_cap"), 0.0)
    v2m = (vol / mc) if mc > 0 else 0.0

    # Score: momentum court (24h) + tendance (7d) + bonus liquidité
    score = (ch24 * 0.65) + (ch7 * 0.35)
    if v2m > 0.08:
        score += 2.0
    if v2m > 0.15:
        score += 1.0

    if score >= 3.0:
        signal = "ACHAT"
        badge = "badge-buy"
    elif score <= -3.0:
        signal = "VENTE"
        badge = "badge-sell"
    else:
        signal = "SURVEILLER"
        badge = "badge-watch"

    confidence = min(95.0, max(55.0, (abs(score) * 10.0) + (10.0 if v2m > 0.10 else 0.0)))
    reasons = []
    reasons.append(f"24h: {ch24:+.2f}%")
    reasons.append(f"7j: {ch7:+.2f}%")
    if v2m > 0.10:
        reasons.append("Liquidité élevée")
    elif v2m > 0.06:
        reasons.append("Liquidité correcte")
    else:
        reasons.append("Liquidité faible")

    return {
        "rank": coin.get("market_cap_rank") or "",
        "id": coin.get("id") or "",
        "name": coin.get("name") or "",
        "symbol": (coin.get("symbol") or "").upper(),
        "price": _safe_float(coin.get("current_price"), 0.0),
        "ch24": ch24,
        "ch7": ch7,
        "volume": vol,
        "market_cap": mc,
        "v2m": v2m,
        "signal": signal,
        "badge": badge,
        "score": round(score, 2),
        "confidence": int(round(confidence, 0)),
        "reasons": reasons[:3],
    }

async def _get_ai_signals_payload() -> dict:
    now_ts = time.time()
    cached = _AI_SIGNALS_CACHE.get("payload")
    if cached and (now_ts - float(_AI_SIGNALS_CACHE.get("ts", 0.0)) < _AI_SIGNALS_CACHE_TTL):
        return cached

    coins = await get_top_50_cryptos()
    signals = [_ai_signal_from_coin(c) for c in (coins or [])]

    # Trier: meilleurs "opportunités" d'abord (|score|, puis market cap rank)
    signals.sort(key=lambda s: (abs(_safe_float(s.get("score"), 0.0)), -_safe_float(s.get("confidence"), 0.0)), reverse=True)

    payload = {
        "updated_at": datetime.utcnow().isoformat(timespec="seconds") + "Z",
        "source": "CoinGecko",
        "count": len(signals),
        "signals": signals,
    }
    _AI_SIGNALS_CACHE["ts"] = now_ts
    _AI_SIGNALS_CACHE["payload"] = payload
    return payload

@app.get("/api/ai-signals-data")
async def ai_signals_data():
    """Endpoint JSON pour rafraîchir la page sans recharger."""
    try:
        return JSONResponse(await _get_ai_signals_payload())
    except Exception as e:
        return JSONResponse({"error": str(e), "signals": [], "count": 0}, status_code=500)

@app.get("/api/ai-signals-trades")
async def ai_signals_trades():
    """Retourne les derniers signaux reçus via /tv-webhook (table trades)."""
    try:
        trades = sql_get_all_trades(limit=50) or []
        now = datetime.utcnow()

        def _parse_dt(ts: str):
            if not ts:
                return None
            try:
                s = ts.replace("Z", "+00:00")
                dt = datetime.fromisoformat(s)
                if dt.tzinfo is not None:
                    dt = dt.astimezone(timezone.utc).replace(tzinfo=None)
                return dt
            except Exception:
                return None

        def _to_float(x):
            try:
                return float(x)
            except Exception:
                return None

        def _tone_for_side(side: str):
            s = (side or "").upper()
            if "BUY" in s or "LONG" in s:
                return "green"
            if "SELL" in s or "SHORT" in s:
                return "red"
            return "gray"

        def _tone_for_status(status: str):
            s = (status or "").upper()
            if "TP" in s:
                return "green"
            if "SL" in s:
                return "red"
            if "OPEN" in s:
                return "blue"
            if "CLOSE" in s or "CLOSED" in s:
                return "gray"
            return "yellow"

        out = []
        for t in trades:
            ts_raw = t.get("timestamp") or ""
            dt = _parse_dt(ts_raw)

            time_ago = "—"
            if dt:
                minutes = int(max(0, (now - dt).total_seconds()) // 60)
                if minutes < 1:
                    time_ago = "à l'instant"
                elif minutes < 60:
                    time_ago = f"il y a {minutes} min"
                else:
                    hours = minutes // 60
                    time_ago = f"il y a {hours} h"

            entry = _to_float(t.get("entry_price"))
            current = _to_float(t.get("current_price"))
            pnl_pct = None
            if entry and current and entry != 0:
                pnl_pct = ((current - entry) / entry) * 100.0

            side = (t.get("side") or "").upper() or "—"
            status = (t.get("status") or "").upper() or "—"

            out.append({
                "id": t.get("id"),
                "timestamp": ts_raw,
                "time_ago": time_ago,
                "symbol": t.get("symbol") or "",
                "side": side,
                "side_tone": _tone_for_side(side),
                "timeframe": t.get("timeframe") or "—",
                "entry_price": entry,
                "current_price": current,
                "pnl_pct": pnl_pct,
                "status": status,
                "status_tone": _tone_for_status(status),
            })

        return JSONResponse({
            "ok": True,
            "generated_at": now.isoformat() + "Z",
            "count": len(out),
            "trades": out
        })
    except Exception as e:
        return JSONResponse({"ok": False, "error": str(e), "trades": []}, status_code=200)

